B.Ng=new A.bA("q1","economic_law","\uacf5\uc815\uac70\ub798\ubc95",null,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.H0,3,'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960 \uc81c5\uc870\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \ub0a8\uc6a9\ud589\uc704\ub97c \u2460 \uac00\uaca9\uc758 \ubd80\ub2f9\ud55c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \ub610\ub294 \uc18c\ube44\uc790\uc774\uc775 \uc800\ud574 \uc6b0\ub824 \ud589\uc704\ub85c \uc720\ud615\ud654\ud558\uace0 \uc788\ub2e4. \ubc18\uba74 \u2463 "\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1\uc801\uc73c\ub85c \ud589\ud558\ub294 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c, \uadf8 \uc790\uccb4\ub85c\ub294 \ubd80\ub2f9\uc131\uc774 \uc778\uc815\ub418\uc9c0 \uc54a\uc544 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4. \ub530\ub77c\uc11c \ub2e4\ub978 \uc120\ud0dd\uc9c0\ub4e4\uc774 \ubaa8\ub450 \ubc95\uc5d0 \uba85\uc2dc\ub41c \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc778 \uac83\uacfc \ub2ec\ub9ac, \uc774 \uc120\ud0dd\uc9c0\ub9cc \ub0a8\uc6a9\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.GA,B.Hd,"2024")
B.Gj=s(["\ubb34\ud6a8\uc778 \ubc95\ub960\ud589\uc704\ub294 \ucd94\uc778\ud574\ub3c4 \ud6a8\ub825\uc774 \uc0dd\uae30\uc9c0 \uc54a\ub294 \uac83\uc774 \uc6d0\uce59","\ucde8\uc18c\ud560 \uc218 \uc788\ub294 \ubc95\ub960\ud589\uc704\ub294 \ucde8\uc18c\ub418\uae30 \uc804\uae4c\uc9c0\ub294 \uc720\ud6a8","\uc81c\ud55c\ub2a5\ub825\uc790\uc758 \ubc95\ub960\ud589\uc704\ub294 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4","\ubb34\ud6a8\uc640 \ucde8\uc18c\ub294 \ud56d\uc0c1 \ud568\uaed8 \ubc1c\uc0dd\ud55c\ub2e4"],t.s)
B.HP=s(["\ub450 \uc81c\ub3c4\ub294 \ubc1c\uc0dd \uc6d0\uc778\uacfc \ud6a8\uacfc \ubc1c\uc0dd \uc2dc\uc810\uc774 \uc804\ud600 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\ub3c4"],t.s)
B.Ge=s(["\ubc95\ub960\ud589\uc704 \ubb34\ud6a8","\ubc95\ub960\ud589\uc704 \ucde8\uc18c"],t.s)
B.Np=new A.bA("q2","civil_law","\ubbfc\ubc95\ucd1d\uce59",null,"\ubbfc\ubc95\uc0c1 \ubc95\ub960\ud589\uc704\uc758 \ubb34\ud6a8\uc640 \ucde8\uc18c\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Gj,3,'\ubb34\ud6a8(\u7121\u6548)\ub294 \ubc95\ub960\ud589\uc704\uac00 \uc131\ub9bd \ub2f9\uc2dc\ubd80\ud130 \ub2f9\uc5f0\ud788 \ud6a8\ub825\uc774 \uc5c6\ub294 \uac83\uc744 \ub9d0\ud558\uace0, \ucde8\uc18c(\u53d6\u6d88)\ub294 \uc77c\ub2e8 \uc720\ud6a8\ud558\uac8c \uc131\ub9bd\ud55c \ubc95\ub960\ud589\uc704\ub97c \ucde8\uc18c\uad8c\uc790\uc758 \uc758\uc0ac\ud45c\uc2dc\ub85c \uc18c\uae09\ud558\uc5ec \ubb34\ud6a8\ub85c \ub9cc\ub4dc\ub294 \uac83\uc744 \ub9d0\ud55c\ub2e4. \uc989 \ubb34\ud6a8\ub294 \ubcc4\ub3c4\uc758 \uc758\uc0ac\ud45c\uc2dc \uc5c6\uc774\ub3c4 \ucc98\uc74c\ubd80\ud130 \ud6a8\ub825\uc774 \uc5c6\uc9c0\ub9cc, \ucde8\uc18c\ub294 \ucde8\uc18c\uad8c\uc790\uac00 \ucde8\uc18c\uad8c\uc744 \ud589\uc0ac\ud558\uae30 \uc804\uae4c\uc9c0\ub294 \uc720\ud6a8\ud55c \ubc95\ub960\ud589\uc704\ub85c \ucde8\uae09\ub41c\ub2e4. \uc774\ucc98\ub7fc \ub450 \uc81c\ub3c4\ub294 \ubc1c\uc0dd \uc6d0\uc778\uacfc \ud6a8\uacfc \ubc1c\uc0dd \uc2dc\uc810\uc774 \uc804\ud600 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\ub3c4\uc774\ubbc0\ub85c, "\ud56d\uc0c1 \ud568\uaed8 \ubc1c\uc0dd\ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ub2e4\ub9cc \uc608\uc678\uc801\uc73c\ub85c \ubb34\ud6a8\ud589\uc704\uc640 \ucde8\uc18c\ud560 \uc218 \uc788\ub294 \ud589\uc704\uac00 \ub3d9\uc2dc\uc5d0 \uc131\ub9bd\ud558\ub294 \uacbd\uc6b0(\uc774\uc911\ud6a8)\uac00 \uc788\uc744 \uc218\ub294 \uc788\uc73c\ub098, \uc774\ub294 \ud56d\uc0c1 \uadf8\ub7f0 \uac83\uc774 \uc544\ub2c8\ub77c \ud2b9\uc815 \uc694\uac74\uc774 \uacb9\uce60 \ub54c\uc5d0 \ud55c\ud55c\ub2e4.',B.HP,B.Ge,"2023")
B.Hy=s(["\uac15\uc810(Strength), \uc57d\uc810(Weakness)","\uae30\ud68c(Opportunity), \uc704\ud611(Threat)","\uac15\uc810, \uae30\ud68c","\uc57d\uc810, \uc704\ud611"],t.s)
B.Ga=s(["\uac15\uc810(Strength)\uacfc \uc57d\uc810(Weakness)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud560 \uc218 \uc788\ub294 \ub0b4\ubd80 \uc5ed\ub7c9"],t.s)
B.Gp=s(["SWOT \ubd84\uc11d","\ub0b4\ubd80/\uc678\ubd80 \uc694\uc778 \uad6c\ubd84"],t.s)
B.Nx=new A.bA("q3","business_admin","\uacbd\uc601\ud559",null,"SWOT \ubd84\uc11d\uc5d0\uc11c \uae30\uc5c5 \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub974\uba74?",B.Hy,0,"SWOT \ubd84\uc11d\uc740 \uae30\uc5c5\uc758 \uacbd\uc601\ud658\uacbd\uc744 \ub0b4\ubd80 \uc694\uc778\uacfc \uc678\ubd80 \uc694\uc778\uc73c\ub85c \ub098\ub204\uc5b4 \ubd84\uc11d\ud558\ub294 \ub300\ud45c\uc801\uc778 \uc804\ub7b5 \uc218\ub9bd \ub3c4\uad6c\uc774\ub2e4. \uc774 \uc911 \uac15\uc810(Strength)\uacfc \uc57d\uc810(Weakness)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud560 \uc218 \uc788\ub294 \ub0b4\ubd80 \uc5ed\ub7c9(\uc790\uae08\ub825, \uae30\uc220\ub825, \uc870\uc9c1\ubb38\ud654, \ube0c\ub79c\ub4dc \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\uace0, \uae30\ud68c(Opportunity)\uc640 \uc704\ud611(Threat)\uc740 \uae30\uc5c5\uc774 \ud1b5\uc81c\ud558\uae30 \uc5b4\ub824\uc6b4 \uc678\ubd80 \ud658\uacbd(\uc2dc\uc7a5 \uc131\uc7a5\ub960, \uacbd\uc7c1 \uac15\ub3c4, \uaddc\uc81c, \uac70\uc2dc\uacbd\uc81c \ub4f1)\uc744 \ud3c9\uac00\ud55c \uac83\uc774\ub2e4. \ub530\ub77c\uc11c \ub0b4\ubd80 \uc5ed\ub7c9\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740 \uac15\uc810\uacfc \uc57d\uc810\uc774\uba70, \uc774\ub97c \ubc14\ud0d5\uc73c\ub85c SO(\uac15\uc810-\uae30\ud68c) \uc804\ub7b5, WT(\uc57d\uc810-\uc704\ud611) \uc804\ub7b5\ucc98\ub7fc \ub0b4\ubd80-\uc678\ubd80 \uc694\uc778\uc744 \uad50\ucc28 \ubd84\uc11d\ud558\uc5ec \uc804\ub7b5\uc744 \ub3c4\ucd9c\ud558\ub294 \uac83\uc774 SWOT \ubd84\uc11d\uc758 \ud575\uc2ec\uc774\ub2e4.",B.Ga,B.Gp,"2025")
B.Fh=s(["\uc0ac\uc5c5\uc790\ub294 \uacc4\uc57d\uccb4\uacb0 \uc2dc \uace0\uac1d\uc774 \uc57d\uad00\uc758 \ub0b4\uc6a9\uc744 \uacc4\uc57d\uc758 \uc885\ub958\uc5d0 \ub530\ub77c \uc77c\ubc18\uc801\uc73c\ub85c \uc608\uc0c1\ud560 \uc218 \uc788\ub294 \ubc29\ubc95\uc73c\ub85c \uba85\uc2dc\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc0ac\uc5c5\uc790\ub294 \uace0\uac1d\uc758 \uc694\uccad\uc774 \uc788\uc73c\uba74 \uc57d\uad00\uc758 \uc0ac\ubcf8\uc744 \uace0\uac1d\uc5d0\uac8c \uad50\ubd80\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4 \ubc0f \uc218\ub3c4\uc0ac\uc5c5\uc758 \uacbd\uc6b0 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub294 \uba74\uc81c\ub418\ub098 \uc911\uc694\ud55c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \uc124\uba85\uc758\ubb34\uae4c\uc9c0 \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0, \ud574\ub2f9 \uc57d\uad00\uc744 \uacc4\uc57d\uc758 \ub0b4\uc6a9\uc73c\ub85c \uc8fc\uc7a5\ud560 \uc218 \uc5c6\ub2e4","\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uc124\uba85\uc758\ubb34\ub294 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.GY=s(['"\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0"\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc774 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub41c\ub2e4'],t.s)
B.Ha=s(["\uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34","\uc124\uba85\uc758\ubb34 \uba74\uc81c\uc0ac\uc720"],t.s)
B.Nt=new A.bA("gen_al_1","economic_law","\uc57d\uad00 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Fh,4,'\uc57d\uad00\ubc95 \uc81c3\uc870\uc5d0 \ub530\ub974\uba74 \uc0ac\uc5c5\uc790\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uc57d\uad00\uc758 \uc911\uc694\ud55c \ub0b4\uc6a9\uc744 \uace0\uac1d\uc774 \uc774\ud574\ud560 \uc218 \uc788\ub3c4\ub85d \uc124\uba85\ud558\uc5ec\uc57c \ud558\uc9c0\ub9cc, "\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\ud558\ub294 \uac83\uc774 \ud604\uc800\ud558\uac8c \uace4\ub780\ud55c \uacbd\uc6b0"\uc5d0\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc774 \uc124\uba85\uc758\ubb34\uac00 \uba74\uc81c\ub41c\ub2e4(\uc81c3\uc870 \uc81c3\ud56d \ub2e8\uc11c). \ub530\ub77c\uc11c "\uc124\uba85\uc758\ubb34\ub294 \uba74\uc81c\ub418\uc9c0 \uc54a\ub294\ub2e4"\uace0 \ub2e8\uc815\ud55c \uc120\ud0dd\uc9c0\uac00 \uc633\uc9c0 \uc54a\uc740 \uc124\uba85\uc774\ub2e4. \ud55c\ud3b8 \uc5ec\uac1d\uc6b4\uc1a1\uc5c5, \uc804\uae30\xb7\uac00\uc2a4\xb7\uc218\ub3c4\uc0ac\uc5c5, \uc6b0\ud3b8\uc5c5 \ub4f1\uc740 \uc57d\uad00\ubc95 \uc81c3\uc870 \uc81c2\ud56d \ub2e8\uc11c\uc5d0 \ub530\ub77c \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub9cc \uba74\uc81c\ub420 \ubfd0, \uc124\uba85\uc758\ubb34\uae4c\uc9c0 \uc790\ub3d9\uc73c\ub85c \uba74\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\ub294 \uc810(\uc120\ud0dd\uc9c0 \u2462)\uc740 \uc2e4\uc81c\ub85c \uc633\uc740 \uc124\uba85\uc774\ubbc0\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\ub3c4\ub85d \uc8fc\uc758\ud574\uc57c \ud55c\ub2e4. \uc989 "\uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34 \uba74\uc81c \uc5c5\uc885"\uacfc "\uc124\uba85\uc758\ubb34 \uba74\uc81c \uc0ac\uc720"\ub294 \uc11c\ub85c \ub2e4\ub978 \uc870\ud56d\uc5d0 \uadfc\uac70\ud55c \ubcc4\uac1c\uc758 \uc608\uc678\ub77c\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec \ud3ec\uc778\ud2b8\ub2e4.',B.GY,B.Ha,null)
B.HS=s(["\uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ud45c\uc900\uc774 \ub420 \uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uadf8 \uc2ec\uc0ac\ub97c \uccad\uad6c\ud560 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc18c\ube44\uc790\ub2e8\uccb4 \ub4f1\uc758 \uc694\uccad\uc774 \uc788\ub294 \uacbd\uc6b0 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uad8c\uace0\ud560 \uc218 \uc788\ub2e4","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub974\uac8c \uc815\ud55c \uc8fc\uc694 \ub0b4\uc6a9\uc774 \uc788\uc73c\uba74 \ud45c\uc900\uc57d\uad00\ubcf4\ub2e4 \uace0\uac1d\uc5d0\uac8c \ub354 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\ub3c4 \uc790\uc720\ub86d\uac8c \uc0ac\uc6a9\ud560 \uc218 \uc788\ub2e4","\ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub974\uac8c \uc815\ud55c \uc8fc\uc694 \ub0b4\uc6a9\uc740 \uace0\uac1d\uc774 \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc5ec\uc57c \ud55c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ud45c\uc900\uc57d\uad00\uc758 \uc0ac\uc6a9\uc744 \ud65c\uc131\ud654\ud558\uae30 \uc704\ud558\uc5ec \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
B.GH=s(["\uadf8\ub7f0 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \ubcc4\ub3c4\ub85c \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc9c0 \uc54a\ub294 \ud55c \ud6a8\ub825\uc774 \uc81c\ud55c\ub41c\ub2e4"],t.s)
B.Gt=s(["\ud45c\uc900\uc57d\uad00","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0"],t.s)
B.Nw=new A.bA("gen_al_2","economic_law","\ud45c\uc900\uc57d\uad00",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.HS,2,'\uc57d\uad00\ubc95 \uc81c19\uc870\uc7583\uc740 \uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub978 \ub0b4\uc6a9\uc758 \uc57d\uad00\uc744 \uc0ac\uc6a9\ud558\uba74\uc11c \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uacbd\uc6b0, \ud45c\uc900\uc57d\uad00\ubcf4\ub2e4 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \uba85\uc2dc\uc801\uc73c\ub85c \ud45c\uc2dc\ud558\uc9c0 \uc54a\uc73c\uba74 \ud45c\uc900\uc57d\uad00\uacfc \uac19\uc740 \ub0b4\uc6a9\uc73c\ub85c \ud569\uc758\ub41c \uac83\uc73c\ub85c \ubcf8\ub2e4\ub294 \ucde8\uc9c0\uc758 \uaddc\uc815\uc744 \ub450\uc5b4 \uace0\uac1d \ubcf4\ud638\ub97c \uaf80\ud558\uace0 \uc788\ub2e4. \uc989 \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\uba74\uc11c \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc744 "\uc790\uc720\ub86d\uac8c" \uc815\ud560 \uc218 \uc788\ub2e4\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\uc73c\uba70, \uc624\ud788\ub824 \uadf8\ub7f0 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \ubcc4\ub3c4\ub85c \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc9c0 \uc54a\ub294 \ud55c \ud6a8\ub825\uc774 \uc81c\ud55c\ub41c\ub2e4. \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0\ub4e4, \uc989 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uc2ec\uc0ac\uccad\uad6c\uad8c, \uacf5\uc815\uc704\uc758 \ud45c\uc900\uc57d\uad00 \uad8c\uace0\uad8c, \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0 \uc81c\uc815\uad8c\uc740 \ubaa8\ub450 \ubc95\uc5d0 \uaddc\uc815\ub41c \uc815\ud655\ud55c \ub0b4\uc6a9\uc774\ub2e4.',B.GH,B.Gt,null)
B.Fd=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ubc94\uc704\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uc5d0 \uad00\ud558\uc5ec \uacac\ubcf8\uc774 \uc81c\uc2dc\ub41c \uacbd\uc6b0 \uadf8 \ubcf4\uc7a5\ub41c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc870\ud56d","\ubc95\ub960\uc5d0 \ub530\ub978 \uace0\uac1d\uc758 \ud574\uc81c\uad8c\xb7\ud574\uc9c0\uad8c\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uadf8 \ud589\uc0ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d","\uacc4\uc57d\ud574\uc9c0 \uc2dc \uacc4\uc57d\ub2f9\uc2dc\uc758 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \ubd80\uc5ec\ud558\ub294 \uc870\ud56d"],t.s)
B.Hg=s(["\uc5b4\ub290 \uc77c\ubc29\uc5d0\uac8c \ud3b8\uc911\ub41c \ubd88\uc774\uc775\uc744 \uc8fc\uc9c0 \uc54a\uace0 \ud615\ud3c9\uc5d0 \ub9de\uac8c \uad8c\ub9ac\xb7\uc758\ubb34\ub97c \ubc30\ubd84\ud55c \uac83"],t.s)
B.IE=s(["\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720"],t.s)
B.N9=new A.bA("gen_al_3","economic_law","\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720",null,"\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubb34\ud6a8\uc778 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Fd,4,'\uc57d\uad00\ubc95\uc774 \ubb34\ud6a8\ub85c \uaddc\uc815\ud558\ub294 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\ub4e4\uc740 \uacf5\ud1b5\uc801\uc73c\ub85c "\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774" \ub610\ub294 "\ubd80\ub2f9\ud558\uac8c" \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc720\ub9ac\ud558\uace0 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud558\uac8c \uc791\uc131\ub41c \uc870\ud56d\uc774\ub77c\ub294 \ud2b9\uc9d5\uc744 \uac00\uc9c4\ub2e4(\uc81c6\uc870~\uc81c14\uc870). \uc190\ud574\ubc30\uc0c1\ubc94\uc704 \uc81c\ud55c, \uacac\ubcf8\xb7\ud488\uc9c8 \uad00\ub828 \ucc45\uc784 \ubc30\uc81c, \uace0\uac1d\uc758 \ubc95\uc815 \ud574\uc81c\xb7\ud574\uc9c0\uad8c \uc81c\ud55c, \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ubd80\uacfc \ub4f1\uc740 \ubaa8\ub450 \uace0\uac1d\uc5d0\uac8c \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \uc804\ud615\uc801 \ubd88\uacf5\uc815\uc870\ud56d\uc774\ub2e4. \ubc18\uba74 \uacc4\uc57d \ud574\uc9c0 \uc2dc "\uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4"\uc5d0\uc11c \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \ubd80\uc5ec\ud558\ub294 \uc870\ud56d\uc740 \uc5b4\ub290 \uc77c\ubc29\uc5d0\uac8c \ud3b8\uc911\ub41c \ubd88\uc774\uc775\uc744 \uc8fc\uc9c0 \uc54a\uace0 \ud615\ud3c9\uc5d0 \ub9de\uac8c \uad8c\ub9ac\xb7\uc758\ubb34\ub97c \ubc30\ubd84\ud55c \uac83\uc774\ubbc0\ub85c \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.',B.Hg,B.IE,null)
B.FN=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub97c \ubc1b\uace0 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uc870\uc0ac \ub300\uc0c1 \ud589\uc704\ub85c \uc778\ud55c \uacbd\uc7c1\uc81c\ud55c\uc0c1\ud0dc\uc758 \uc790\ubc1c\uc801 \ud574\uc18c\ub97c \uc704\ud558\uc5ec \ub3d9\uc758\uc758\uacb0\uc744 \uc2e0\uccad\ud560 \uc218 \uc788\ub2e4","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \ub3d9\uc758\uc758\uacb0\uc744 \ud560 \uc218 \uc5c6\ub2e4","\ub3d9\uc758\uc758\uacb0\uc740 \ud574\ub2f9 \ud589\uc704\uac00 \uc774 \ubc95\uc5d0 \uc704\ubc18\ub41c\ub2e4\uace0 \uc778\uc815\ud55c \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub3d9\uc758\uc758\uacb0\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \uc788\uae30 \uc804\uc774\ub77c\ub3c4 \uc2e0\uccad\uc778\uc740 \uc2e0\uccad\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Ir=s(["\ub3d9\uc758\uc758\uacb0\uc740 \uc624\ud788\ub824 \uc704\ubc95\uc131 \uc5ec\ubd80\ub97c \ud655\uc815\ud558\uc9c0 \uc54a\uace0 \uc808\ucc28\ub97c \uc870\uae30\uc5d0 \uc885\uacb0\ud558\ub294 \uac83\uc774 \ud575\uc2ec \ucde8\uc9c0"],t.s)
B.Gs=s(["\ub3d9\uc758\uc758\uacb0\uc81c\ub3c4"],t.s)
B.N6=new A.bA("gen_pc_1","economic_law","\ub3d9\uc758\uc758\uacb0",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ub3d9\uc758\uc758\uacb0\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.FN,2,'\ub3d9\uc758\uc758\uacb0 \uc81c\ub3c4(\uacf5\uc815\uac70\ub798\ubc95 \uc81c89\uc870~\uc81c91\uc870)\ub294 \uc870\uc0ac\ub97c \ubc1b\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \uc2dc\uc815\ubc29\uc548\uc744 \ub9c8\ub828\ud574 \uc81c\ucd9c\ud558\uba74, \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc704\ubc95 \uc5ec\ubd80\ub97c \ud655\uc815 \uc9d3\uc9c0 \uc54a\uc740 \ucc44 \uadf8 \uc2dc\uc815\ubc29\uc548\uacfc \uac19\uc740 \ucde8\uc9c0\ub85c \uc758\uacb0\ud558\uc5ec \uc0ac\uac74\uc744 \uc2e0\uc18d\ud558\uac8c \uc885\uacb0\ud558\ub294 \uc81c\ub3c4\uc774\ub2e4. \ub530\ub77c\uc11c "\ub3d9\uc758\uc758\uacb0\uc740 \ud574\ub2f9 \ud589\uc704\uac00 \ubc95\uc5d0 \uc704\ubc18\ub41c\ub2e4\uace0 \uc778\uc815\ud55c \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4 \u2014 \ub3d9\uc758\uc758\uacb0\uc740 \uc624\ud788\ub824 \uc704\ubc95\uc131 \uc5ec\ubd80\ub97c \ud655\uc815\ud558\uc9c0 \uc54a\uace0 \uc808\ucc28\ub97c \uc870\uae30\uc5d0 \uc885\uacb0\ud558\ub294 \uac83\uc774 \ud575\uc2ec \ucde8\uc9c0\uc774\uae30 \ub54c\ubb38\uc774\ub2e4. \ub2e4\ub9cc \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704(\ub2f4\ud569)\ucc98\ub7fc \uc0ac\ud68c\uc801 \ud3d0\ud574\uac00 \ud070 \ud589\uc704\ub294 \ub3d9\uc758\uc758\uacb0 \ub300\uc0c1\uc5d0\uc11c \uc6d0\uce59\uc801\uc73c\ub85c \uc81c\uc678\ub418\uba70, \uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc774\ud589\ud558\uc9c0 \uc54a\uc73c\uba74 \uacf5\uc815\uc704\uac00 \ub3d9\uc758\uc758\uacb0\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4\ub294 \uc810\ub3c4 \ud568\uaed8 \uae30\uc5b5\ud574\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.Ir,B.Gs,null)
B.He=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc95 \uc704\ubc18 \uc0ac\uc5c5\uc790\uac00 \ud569\ubcd1\uc73c\ub85c \uc18c\uba78\ud55c \uacbd\uc6b0 \uc874\uc18d\ud558\ub294 \ud68c\uc0ac\uc5d0 \ub300\ud558\uc5ec \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\xb7\uc9d5\uc218\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ubc1b\uc740 \ud68c\uc0ac\uac00 \ubd84\ud560\ub418\ub294 \uacbd\uc6b0 \ubd84\ud560\ub418\ub294 \ud68c\uc0ac\uc640 \uc2e0\uc124\ud68c\uc0ac\ub294 \uadf8 \uacfc\uc9d5\uae08\uc744 \uc5f0\ub300\ud558\uc5ec \ub0a9\ubd80\ud560 \ucc45\uc784\uc744 \uc9c4\ub2e4","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uc758\ubb34\uc790\uac00 \ubb34\uc790\ub825\uc774 \ub418\uc5b4 \uc9d5\uc218\uac00 \ubd88\uac00\ub2a5\ud574\uc9c4 \uacbd\uc6b0 \uacb0\uc190\ucc98\ubd84\uc744 \ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uae30\ud55c\uc758 \uc5f0\uae30\ub97c \uc2e0\uccad\ud558\ub824\ub294 \uc790\ub294 \ub0a9\ubd80\ud1b5\uc9c0\ub97c \ubc1b\uc740 \ub0a0\ubd80\ud130 60\uc77c \uc774\ub0b4\uc5d0 \uc2e0\uccad\ud558\uc5ec\uc57c \ud55c\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud615\ubc8c\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c \ub3d9\uc77c\ud55c \ud589\uc704\uc5d0 \ub300\ud558\uc5ec \ubc8c\uae08\uacfc \uacfc\uc9d5\uae08\uc744 \ud568\uaed8 \ubd80\uacfc\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.Fn=s(["\uacfc\uc9d5\uae08\uc740 \ud615\uc0ac\ucc98\ubc8c\uc774 \uc544\ub2c8\ub77c \ubc95 \uc704\ubc18\uc73c\ub85c \uc5bb\uc740 \ubd80\ub2f9\uc774\ub4dd\uc744 \ud658\uc218\ud558\uace0 \uc704\ubc18\ud589\uc704\ub97c \uc5b5\uc9c0\ud558\uae30 \uc704\ud55c \ud589\uc815\uc81c\uc7ac"],t.s)
B.HQ=s(["\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8"],t.s)
B.Nq=new A.bA("gen_pc_2","economic_law","\uacfc\uc9d5\uae08",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacfc\uc9d5\uae08\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.He,4,"\uacfc\uc9d5\uae08\uc740 \ud615\uc0ac\ucc98\ubc8c\uc774 \uc544\ub2c8\ub77c \ubc95 \uc704\ubc18\uc73c\ub85c \uc5bb\uc740 \ubd80\ub2f9\uc774\ub4dd\uc744 \ud658\uc218\ud558\uace0 \uc704\ubc18\ud589\uc704\ub97c \uc5b5\uc9c0\ud558\uae30 \uc704\ud55c \ud589\uc815\uc81c\uc7ac(\ud589\uc815\uc0c1 \uc81c\uc7ac\uae08)\uc758 \uc131\uaca9\uc744 \uac16\ub294\ub2e4\ub294 \uac83\uc774 \ub300\ubc95\uc6d0 \ubc0f \ud5cc\ubc95\uc7ac\ud310\uc18c\uc758 \uc77c\uad00\ub41c \uc785\uc7a5\uc774\ub2e4. \ub530\ub77c\uc11c \ub3d9\uc77c\ud55c \uc704\ubc18\ud589\uc704\uc5d0 \ub300\ud574 \ud615\uc0ac\ucc98\ubc8c(\ubc8c\uae08)\uacfc \uacfc\uc9d5\uae08\uc774 \ud568\uaed8 \ubd80\uacfc\ub418\ub354\ub77c\ub3c4, \uc774\ub294 \uc131\uc9c8\uc774 \ub2e4\ub978 \ubcc4\uac1c\uc758 \uc81c\uc7ac\ub97c \ubcd1\uacfc\ud558\ub294 \uac83\uc774\ubbc0\ub85c \uc774\uc911\ucc98\ubc8c\uae08\uc9c0\uc6d0\uce59\uc5d0 \uc704\ubc18\ub418\uc9c0 \uc54a\ub294\ub2e4. \ubc18\uba74 \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0\ub4e4 \u2014 \ud569\ubcd1\xb7\ubd84\ud560 \uc2dc \uacfc\uc9d5\uae08 \uc2b9\uacc4, \ubb34\uc790\ub825\uc5d0 \ub530\ub978 \uacb0\uc190\ucc98\ubd84, 60\uc77c \uc774\ub0b4 \ub0a9\ubd80\uae30\ud55c \uc5f0\uae30 \uc2e0\uccad \u2014 \uc740 \ubaa8\ub450 \uacf5\uc815\uac70\ub798\ubc95\ub839\uc0c1 \uc2e4\uc81c\ub85c \uc778\uc815\ub418\ub294 \uc81c\ub3c4\uc774\ubbc0\ub85c \uc633\uc740 \uc124\uba85\uc774\ub2e4.",B.Fn,B.HQ,null)
B.Hs=s(["\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uae08\uc9c0 \uaddc\uc815\uc744 \uc704\ubc18\ud558\uc5ec \uc190\ud574\ub97c \uc785\uc740 \uc790\uac00 \uc788\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\ub294 \uc790\uc2e0\uc5d0\uac8c \uace0\uc758 \ub610\ub294 \uacfc\uc2e4\uc774 \uc5c6\uc5c8\uc74c\uc744 \ub4e4\uc5b4 \ucc45\uc784\uc744 \uba74\ud560 \uc218 \uc5c6\ub2e4","\uc790\uc9c4\uc2e0\uace0 \ub4f1\uc73c\ub85c \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc744 \uac10\uba74\ubc1b\uc740 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc740 \ubc1c\uc0dd\ud55c \uc190\ud574\ub97c \ucd08\uacfc\ud558\uc9c0 \uc54a\ub294 \ubc94\uc704\ub85c \ud55c\uc815\ub420 \uc218 \uc788\ub2e4","\ubc95\uc6d0\uc740 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc758 \uc18c\uac00 \uc81c\uae30\ub41c \ub54c \ud544\uc694\ud558\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \ud574\ub2f9 \uc0ac\uac74\uae30\ub85d\uc758 \uc1a1\ubd80\ub97c \uc694\uad6c\ud560 \uc218 \uc788\ub2e4","\uc190\ud574\uac00 \ubc1c\uc0dd\ud55c \uc0ac\uc2e4\uc740 \uc778\uc815\ub418\ub098 \uc190\ud574\uc561\uc744 \uc99d\uba85\ud558\uae30 \uc704\ud574 \ud544\uc694\ud55c \uc0ac\uc2e4\uc744 \uc99d\uba85\ud558\ub294 \uac83\uc774 \uc0ac\uc548\uc758 \uc131\uc9c8\uc0c1 \uace4\ub780\ud55c \uacbd\uc6b0, \ubc95\uc6d0\uc740 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\ub97c \uae30\uac01\ud558\uc5ec\uc57c \ud55c\ub2e4","\ubc95\uc6d0\uc740 \ub2f9\uc0ac\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc790\ub8cc\uc81c\ucd9c\uba85\ub839\uc5d0 \ub530\ub974\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0 \uc790\ub8cc\uc758 \uae30\uc7ac\uc5d0 \uad00\ud55c \uc0c1\ub300\ubc29\uc758 \uc8fc\uc7a5\uc744 \uc9c4\uc2e4\ud55c \uac83\uc73c\ub85c \uc778\uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Hc=s(['\ubcc0\ub860 \uc804\uccb4\uc758 \ucde8\uc9c0\uc640 \uc99d\uac70\uc870\uc0ac\uc758 \uacb0\uacfc\uc5d0 \uae30\ucd08\ud558\uc5ec "\uc0c1\ub2f9\ud55c \uc190\ud574\uc561"\uc744 \uc778\uc815\ud560 \uc218 \uc788\ub3c4\ub85d'],t.s)
B.HB=s(["\uc190\ud574\ubc30\uc0c1\ucc45\uc784","\uc190\ud574\uc561 \uc778\uc815"],t.s)
B.Na=new A.bA("gen_pc_3","economic_law","\uc190\ud574\ubc30\uc0c1\ucc45\uc784",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc190\ud574\ubc30\uc0c1 \ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Hs,3,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c115\uc870\ub294 \ubc95 \uc704\ubc18\ud589\uc704\ub85c \uc190\ud574\uac00 \ubc1c\uc0dd\ud55c \uc0ac\uc2e4\uc740 \uc778\uc815\ub418\uc9c0\ub9cc \uadf8 \uc190\ud574\uc561\uc744 \uc99d\uba85\ud558\ub294 \uac83\uc774 \uc0ac\uc548\uc758 \uc131\uc9c8\uc0c1 \uadf9\ud788 \uace4\ub780\ud55c \uacbd\uc6b0, \ubc95\uc6d0\uc774 \uccad\uad6c\ub97c \uae30\uac01\ud558\uc9c0 \uc54a\uace0 \ubcc0\ub860 \uc804\uccb4\uc758 \ucde8\uc9c0\uc640 \uc99d\uac70\uc870\uc0ac\uc758 \uacb0\uacfc\uc5d0 \uae30\ucd08\ud558\uc5ec "\uc0c1\ub2f9\ud55c \uc190\ud574\uc561"\uc744 \uc778\uc815\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\ub294 \uc190\ud574\uc561 \uc778\uc815 \uc81c\ub3c4\ub97c \ub450\uace0 \uc788\ub2e4. \uc774\ub294 \uc190\ud574\uc758 \ubc1c\uc0dd\uc740 \uba85\ubc31\ud558\uc9c0\ub9cc \uc815\ud655\ud55c \uc561\uc218 \uc0b0\uc815\uc774 \uc5b4\ub824\uc6b4 \ud53c\ud574\uc790\ub97c \ub450\ud141\uac8c \ubcf4\ud638\ud558\uae30 \uc704\ud55c \ud2b9\uce59\uc73c\ub85c, \ubbfc\uc0ac\uc18c\uc1a1\uc758 \uc77c\ubc18 \uc99d\uba85\ucc45\uc784 \uc6d0\uce59\uc5d0 \ub300\ud55c \uc911\uc694\ud55c \uc608\uc678\ub2e4. \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0(\uace0\uc758\xb7\uacfc\uc2e4 \uc785\uc99d\ucc45\uc784 \uc804\ud658, \uae30\ub85d\uc1a1\ubd80 \uc694\uad6c\uad8c, \uc790\ub8cc\uc81c\ucd9c\uba85\ub839 \uc704\ubc18 \uc2dc \uc0c1\ub300\ubc29 \uc8fc\uc7a5 \uc778\uc815)\ub294 \ubaa8\ub450 \uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2e4\uc81c\ub85c \uc778\uc815\ub418\ub294 \uc190\ud574\ubc30\uc0c1 \ud2b9\uce59\ub4e4\uc774\ub2e4.',B.Hc,B.HB,null)
B.H6=s(["\u3131, \u3134, \u3137","\u3131, \u3137, \u3139","\u3134, \u3137, \u3139","\u3134, \u3139, \u3141","\u3137, \u3139, \u3141"],t.s)
B.H3=s(["\uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\xb7\ubd88\uc774\uc775\uc81c\uacf5\xb7\uacbd\uc601\uac04\uc12d 5\uac00\uc9c0\ub85c \uc2dc\ud589\ub839\uc5d0 \uc5f4\uac70"],t.s)
B.HK=s(["\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \ud558\uc704\uc720\ud615"],t.s)
B.Nj=new A.bA("gen_ub_1","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ud615 \uc911 \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uad6c\uc785\uac15\uc81c  \u3134. \ubd80\ub2f9\uc5fc\ub9e4  \u3137. \uc774\uc775\uc81c\uacf5\uac15\uc694  \u3139. \ud310\ub9e4\ubaa9\ud45c\uac15\uc81c  \u3141. \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c",B.H6,1,'\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 "\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9"\uc740 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1 \uc6b0\uc6d4\uc801 \uc9c0\uc704\ub97c \uc774\uc6a9\ud574 \uc0c1\ub300\ubc29\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \ubd88\uc774\uc775\uc744 \uc8fc\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc73c\ub85c, \uadf8 \ud558\uc704 \uc720\ud615\uc740 \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\xb7\ubd88\uc774\uc775\uc81c\uacf5\xb7\uacbd\uc601\uac04\uc12d 5\uac00\uc9c0\ub85c \uc2dc\ud589\ub839\uc5d0 \uc5f4\uac70\ub418\uc5b4 \uc788\ub2e4. \ubc18\uba74 \ubd80\ub2f9\uc5fc\ub9e4(\u3134)\ub294 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uc5d0 \uc18d\ud558\uace0, \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c(\u3141) \uc790\uccb4\ub3c4 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uacfc\ub294 \ubcc4\uac1c\uc758 \ub300\ubd84\ub958\uc774\ubbc0\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4. \ub530\ub77c\uc11c \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c(\u3131, \u3137, \u3139)\ub9cc \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud558\uba70, \uc774\ub294 \uc2e4\ubb34\uc0c1\uc73c\ub85c\ub3c4 \uac00\ub9f9\ubcf8\ubd80\xb7\ub300\ud615\uc720\ud1b5\uc5c5\uccb4\uac00 \uac00\ub9f9\uc810\xb7\ub0a9\ud488\uc5c5\uccb4\uc5d0 \ud589\ud558\ub294 \uac11\uc9c8 \uaddc\uc81c\uc758 \ud575\uc2ec \uadfc\uac70\uc870\ud56d\uc73c\ub85c \uc790\uc8fc \ucd9c\uc81c\ub41c\ub2e4.',B.H3,B.HK,null)
B.Gy=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \uac00\uc9c0\uae09\uae08\xb7\ub300\uc5ec\uae08 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ubd80\ub3d9\uc0b0\xb7\uc720\uac00\uc99d\uad8c\xb7\uc0c1\ud488 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \ub9e4\ub9e4\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \uc778\ub825\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uc9c1\uc811 \uac70\ub798\ud558\uba74 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud568\uc5d0\ub3c4 \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\ub97c \ub9e4\uac1c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1 \uc9c0\uae09\ub418\ub294 \ub300\uac00\ubcf4\ub2e4 \ub0ae\uc740 \ub300\uac00\ub85c \uc790\uae30\uc758 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uacf5\uae09\ud558\ub294 \ud589\uc704"],t.s)
B.IS=s(["\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778\xb7\uacc4\uc5f4\uc0ac\uc5d0 \ub300\ud55c \uc774\uc775 \ubab0\uc544\uc8fc\uae30\uac00 \ud575\uc2ec\uc774\uace0 \ubd80\ub2f9\uc5fc\ub9e4\ub294 \uc2dc\uc7a5\uc5d0\uc11c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ucd95\ucd9c\ud558\ub824\ub294 \uac00\uaca9\uc815\ucc45"],t.s)
B.H_=s(["\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704","\ubd80\ub2f9\uc5fc\ub9e4\uc640 \uad6c\ubd84"],t.s)
B.N7=new A.bA("gen_ub_2","economic_law","\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uc9c0\uc6d0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Gy,4,'\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ub300\ud574 \uc790\uae08\xb7\uc790\uc0b0\xb7\uc778\ub825\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\uac70\ub098, \ud544\uc694 \uc774\uc0c1\uc758 \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud574 \uc774\uc775\uc744 \ubab0\uc544\uc8fc\ub294 \ubc29\uc2dd\uc73c\ub85c \ubd80\ub2f9\ud558\uac8c \uc9c0\uc6d0\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \ubc18\uba74 \ub9c8\uc9c0\ub9c9 \uc120\ud0dd\uc9c0\ucc98\ub7fc \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1 \uc9c0\uae09\ub418\ub294 \ub300\uac00\ubcf4\ub2e4 \ub0ae\uc740 \uac00\uaca9\uc5d0 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uacf5\uae09\ud558\ub294 \ud589\uc704\ub294 "\ubd80\ub2f9\uc5fc\ub9e4"\ub85c\uc11c, \uc774\ub294 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \uc2dc\uc7a5\uc5d0\uc11c \ubc30\uc81c\ud558\ub824\ub294 \ubaa9\uc801\uc758 "\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c" \uc720\ud615\uc5d0 \ud574\ub2f9\ud55c\ub2e4. \ub450 \uc720\ud615 \ubaa8\ub450 "\ubd80\ub2f9\ud558\uac8c \ub0ae\uc740/\uc720\ub9ac\ud55c \uc870\uac74"\uc774\ub77c\ub294 \uacf5\ud1b5\uc810 \ub54c\ubb38\uc5d0 \ud5f7\uac08\ub9ac\uae30 \uc27d\uc9c0\ub9cc, \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\ub294 \ud2b9\uc218\uad00\uacc4\uc778\xb7\uacc4\uc5f4\uc0ac\uc5d0 \ub300\ud55c \uc774\uc775 \ubab0\uc544\uc8fc\uae30\uac00 \ud575\uc2ec\uc774\uace0 \ubd80\ub2f9\uc5fc\ub9e4\ub294 \uc2dc\uc7a5\uc5d0\uc11c \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ucd95\ucd9c\ud558\ub824\ub294 \uac00\uaca9\uc815\ucc45\uc774\ub77c\ub294 \uc810\uc5d0\uc11c \uaddc\uc81c \ubaa9\uc801\uc774 \ub2e4\ub974\ub2e4.',B.IS,B.H_,null)
B.HR=s(["\ubd80\ub2f9\ud558\uac8c \uac70\ub798\uc0c1\ub300\ubc29\uc774 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc758 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \uc54a\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub294 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\uc9c0\uc5ed\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \ud589\uc704\ub294 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc744 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc640\ub9cc \uac70\ub798\ud558\ub3c4\ub85d \uad6c\uc18d\ud558\ub294 \uac83\uc740 \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.If=s(["\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \ubd09\uc1c4\ud574 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uad6c\uc870 \uc790\uccb4\ub97c \uc65c\uace1"],t.s)
B.J1=s(["\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798"],t.s)
B.Nu=new A.bA("gen_ub_3","economic_law","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.HR,0,'\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\ucc98 \uc120\ud0dd\uc774\ub098 \ud310\ub9e4 \uc9c0\uc5ed\xb7\ub300\uc0c1\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud558\uba70, \uadf8 \ub300\ud45c\uc801 \ud558\uc704 \uc720\ud615\uc774 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798(\uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \uad6c\uc18d)\uc640 \uac70\ub798\uc9c0\uc5ed\xb7\uac70\ub798\uc0c1\ub300\ubc29 \uc81c\ud55c\uc774\ub2e4. \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc720\ud1b5\ub9dd \uc811\uadfc\uc744 \ubd09\uc1c4\ud574 \uc2dc\uc7a5\uc758 \uacbd\uc7c1\uad6c\uc870 \uc790\uccb4\ub97c \uc65c\uace1\ud560 \uc218 \uc788\uc5b4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub418\uba70, "\ud56d\uc0c1 \uc801\ubc95"\ud558\ub2e4\ub294 \uc124\uba85(\uc120\ud0dd\uc9c0 \u2462)\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ub610\ud55c \uac70\ub798\uc9c0\uc5ed \uc81c\ud55c\uc740 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc774 \uc544\ub2c8\ub77c \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \uc790\uccb4\uc758 \ud558\uc704\uc720\ud615\uc774\uace0(\uc120\ud0dd\uc9c0 \u2461\ub294 \uc624\ub2f5), \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc640\ub294 \ubcc4\uac1c\uc758 \ub3c5\ub9bd\ub41c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ud615\uc774\ub77c\ub294 \uc810(\uc120\ud0dd\uc9c0 \u2463\ub3c4 \uc624\ub2f5)\uc744 \ud568\uaed8 \uc815\ub9ac\ud574\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.If,B.J1,null)
B.IC=s(["\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc0ac\uc2e4\uc744 \uc790\uc9c4\uc2e0\uace0\ud558\uac70\ub098 \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc790\uc5d0 \ub300\ud574\uc11c\ub294 \uc2dc\uc815\uc870\uce58 \ub610\ub294 \uacfc\uc9d5\uae08\uc744 \uac10\uacbd\ud558\uac70\ub098 \uba74\uc81c\ud560 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74 \ud61c\ud0dd\uc740 \ud615\uc0ac\uace0\ubc1c\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc5b4 \uace0\ubc1c\uc744 \uba74\uc81c\ud560 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uac10\uba74\uc81c\ub3c4\ub294 \ub3d9\uc77c\ud55c \uc0ac\uc5c5\uc790\uac00 \ubc18\ubcf5\uc801\uc73c\ub85c \uc790\uc9c4\uc2e0\uace0\ud558\ub294 \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc99d\uac70\uc81c\uacf5 \ub4f1\uc758 \ubc29\ubc95\uc73c\ub85c \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc790\uc5d0 \ub300\ud558\uc5ec \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc758 \uac10\uacbd \ub610\ub294 \uba74\uc81c\uac00 \uac00\ub2a5\ud558\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc758 \ub3d9\uc758 \uc5c6\uc774 \uadf8 \uc2e0\uc6d0 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \ub2e4\ub978 \ubaa9\uc801\uc73c\ub85c \uc0ac\uc6a9\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4"],t.s)
B.Iu=s(["\ubc18\ubcf5 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74\uc744 \ubc30\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \uaddc\uc815"],t.s)
B.Gn=s(["\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74(\ub9ac\ub2c8\uc5b8\uc2dc)"],t.s)
B.No=new A.bA("gen_ca_1","economic_law","\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc5d0 \ub300\ud55c \uac10\uba74\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.IC,2,'\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74\uc81c\ub3c4(\ub9ac\ub2c8\uc5b8\uc2dc)\ub294 \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \uc0ac\uc5c5\uc790\uac00 \uc2a4\uc2a4\ub85c \uadf8 \uc0ac\uc2e4\uc744 \uc2e0\uace0\ud558\uac70\ub098 \uc870\uc0ac\uc5d0 \ud611\uc870\ud558\uba74 \uc2dc\uc815\uc870\uce58\xb7\uacfc\uc9d5\uae08\uc744 \uac10\uacbd \ub610\ub294 \uba74\uc81c\ud574\uc8fc\ub294 \uc81c\ub3c4\ub85c, \ub2f4\ud569\uc758 \uc740\ubc00\uc131\uc744 \uae68\ub728\ub824 \uc801\ubc1c\ub960\uc744 \ub192\uc774\uae30 \uc704\ud574 \ub3c4\uc785\ub418\uc5c8\ub2e4. \uadf8\ub7f0\ub370 \ub3d9\uc77c\ud55c \uc0ac\uc5c5\uc790\uac00 \uc5ec\ub7ec \ucc28\ub840 \ubc18\ubcf5\uc801\uc73c\ub85c \ub2f4\ud569\uc5d0 \uac00\ub2f4\ud55c \ud6c4 \ub9e4\ubc88 \uc790\uc9c4\uc2e0\uace0\ub85c \uac10\uba74\ubc1b\ub294 \uacbd\uc6b0\uae4c\uc9c0 \ubb34\uc870\uac74 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud55c\ub2e4\uba74 \uc624\ud788\ub824 \ub2f4\ud569\uc744 \uc870\uc7a5\ud558\ub294 \uc5ed\ud6a8\uacfc\uac00 \uc0dd\uae38 \uc218 \uc788\uc73c\ubbc0\ub85c, \uc2dc\ud589\ub839\uc740 \uc77c\uc815 \uc694\uac74 \ud558\uc5d0 \ubc18\ubcf5 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74\uc744 \ubc30\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \uaddc\uc815\ud558\uace0 \uc788\ub2e4. \ub530\ub77c\uc11c "\ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\uc5ec\uc57c \ud55c\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4.',B.Iu,B.Gn,null)
B.I5=s(["\ubd88\ud669\uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815","\uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c","\uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654","\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1","\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"],t.s)
B.IU=s(['"\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"\ucc98\ub7fc \ud2b9\uc815 \uae30\uc5c5\uc758 \uc0ac\uc801 \uc774\uc775\uc744 \uc704\ud55c \ubaa9\uc801\uc740 \uc778\uac00\uc0ac\uc720\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4'],t.s)
B.H4=s(["\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720"],t.s)
B.N8=new A.bA("gen_ca_2","economic_law","\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc81c\ub3c4",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uac00 \uc608\uc678\uc801\uc73c\ub85c \ud5c8\uc6a9\ub420 \uc218 \uc788\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc778\uac00 \ubaa9\uc801\uc73c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.I5,4,'\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub418\uc9c0\ub9cc, \uacf5\uc815\uac70\ub798\ubc95 \uc81c40\uc870 \uc81c2\ud56d\uc740 \uc608\uc678\uc801\uc73c\ub85c \u2460 \ubd88\ud669 \uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815, \u2461 \uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c, \u2462 \uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654, \u2463 \uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1\uc744 \ubaa9\uc801\uc73c\ub85c \ud558\uace0 \ub300\ud1b5\ub839\ub839\uc774 \uc815\ud558\ub294 \uc694\uac74\uc744 \uac16\ucd98 \uacbd\uc6b0\uc5d0 \ud55c\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc778\uac00\ub97c \ubc1b\uc544 \uacf5\ub3d9\ud589\uc704\ub97c \ud560 \uc218 \uc788\ub3c4\ub85d \ud5c8\uc6a9\ud558\uace0 \uc788\ub2e4. \uc774 \uc778\uac00\uc81c\ub3c4\ub294 \uc5b4\ub514\uae4c\uc9c0\ub098 \uc0b0\uc5c5 \uc804\uccb4\uc758 \ud6a8\uc728\uc131\uc774\ub098 \uc911\uc18c\uae30\uc5c5 \ubcf4\ud638\ucc98\ub7fc \uacf5\uc775\uc801 \ubaa9\uc801\uc774 \uc788\ub294 \uc608\uc678\uc801\uc778 \uacbd\uc6b0\uc5d0\ub9cc \uc801\uc6a9\ub418\ub294 \uac83\uc774\uc9c0, "\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"\ucc98\ub7fc \ud2b9\uc815 \uae30\uc5c5\uc758 \uc0ac\uc801 \uc774\uc775\uc744 \uc704\ud55c \ubaa9\uc801\uc740 \uc778\uac00\uc0ac\uc720\ub85c \uc778\uc815\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.IU,B.H4,null)
B.Hh=s(["\uc2dc\uc7a5\uc810\uc720\uc728 55%\uc778 \ub2e8\uc77c \uc0ac\uc5c5\uc790 A","\uc2dc\uc7a5\uc810\uc720\uc728 40%\uc778 B\uc640 \uc2dc\uc7a5\uc810\uc720\uc728 15%\uc778 C\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 3\uc704 \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\ubcf4\ub2e4 \ud070 \uacbd\uc6b0\uc758 B, C","\uc2dc\uc7a5\uc810\uc720\uc728 12%\uc5d0 \ubd88\uacfc\ud558\uace0 \uc2dc\uc7a5\uc810\uc720\uc728 \uc21c\uc704\uac00 3\uc704 \uc774\ud558\uc778 D","\uc2dc\uc7a5\uc810\uc720\uc728\uc774 \uac01\uac01 35%, 20%\uc778 3 \uc774\ud558\uc758 \uc0ac\uc5c5\uc790 \uc911 \ud558\ub098\uc778 E","\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0 \uc810\uc720\uc728\uc774 40%\uc778 F"],t.s)
B.I8=s(["\uc21c\uc704\ub3c4 3\uc704 \ubc16\uc778 \uc0ac\uc5c5\uc790\ub294 \uc704 \ub450 \uc694\uac74 \uc911 \uc5b4\ub290 \uac83\ub3c4 \ucda9\uc871\ud558\uc9c0 \ubabb\ud558\ubbc0\ub85c \ucd94\uc815 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678"],t.s)
B.I6=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815"],t.s)
B.Nl=new A.bA("gen_md_1","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\ub294? (\uacc4\uc5f4\uad00\uacc4\ub294 \uc5c6\ub2e4\uace0 \uac00\uc815\ud558\uba70, \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc5f0\uac04 \ub9e4\ucd9c\uc561 \uae30\uc900)",B.Hh,2,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c6\uc870\ub294 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \u2460 \uc2dc\uc7a5\uc810\uc720\uc728\uc774 1\uc704\uc778 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\uc774 50% \uc774\uc0c1\uc774\uac70\ub098, \u2461 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0c1\uc704 3\uac1c \uc774\ud558 \uc0ac\uc5c5\uc790\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 75% \uc774\uc0c1\uc778 \uacbd\uc6b0(\ub2e4\ub9cc \uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uc81c\uc678)\uc5d0 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ud55c\ub2e4\uace0 \uaddc\uc815\ud55c\ub2e4. \uc774 \uae30\uc900\uc744 \uc801\uc6a9\ud558\uba74 A(55%)\ub294 \u2460\uc5d0 \ud574\ub2f9\ud558\uace0, B(23%)\xb7C(70%)\xb7D(4%)\xb7E(6%)\xb7F(40%) \uac19\uc740 \uc0ac\ub840\uc5d0\uc11c\ub3c4 \uc0c1\uc704 3\uac1c \ud569\uc0b0 \uc810\uc720\uc728\uacfc 10% \ubbf8\ub9cc \uc81c\uc678 \uaddc\uc815\uc744 \uc801\uc6a9\ud574 \ud310\ub2e8\ud574\uc57c \ud55c\ub2e4. \uc2dc\uc7a5\uc810\uc720\uc728\uc774 \ub0ae\uace0(\uc608: 12%) \uc21c\uc704\ub3c4 3\uc704 \ubc16\uc778 \uc0ac\uc5c5\uc790\ub294 \uc704 \ub450 \uc694\uac74 \uc911 \uc5b4\ub290 \uac83\ub3c4 \ucda9\uc871\ud558\uc9c0 \ubabb\ud558\ubbc0\ub85c \ucd94\uc815 \ub300\uc0c1\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec\uc774\ub2e4.",B.I8,B.I6,null)
B.HH=s(["\uac70\ub798\uc758 \uac1d\uccb4\ubcc4\ub85c \uac70\ub798\ub418\ub294 \uc0c1\ud488\uc758 \uc885\ub958 \ubc0f \uc131\uc9c8\uc5d0 \ub530\ub77c \uad6c\ubd84\ub420 \uc218 \uc788\ub294 \uac70\ub798\ubd84\uc57c\ub97c \ub9d0\ud55c\ub2e4","\uc218\uc694\uc790\uac00 \uac00\uaca9 \uc778\uc0c1\uc5d0 \ub300\uc751\ud574 \ub2e4\ub978 \uc0c1\ud488\uc73c\ub85c \ub300\uccb4\ud560 \uc218 \uc788\ub294 \uc815\ub3c4(\uc218\uc694\ub300\uccb4\uc131)\ub97c \uc8fc\uc694 \ud310\ub2e8\uae30\uc900\uc73c\ub85c \uc0bc\ub294\ub2e4","\uacf5\uae09\uc790\uc758 \uc0dd\uc0b0\uc124\ube44 \uc804\ud658 \uac00\ub2a5\uc131 \ub4f1 \uacf5\uae09\ub300\uccb4\uc131\ub3c4 \uc2dc\uc7a5 \ud68d\uc815\uc5d0\uc11c \ud568\uaed8 \uace0\ub824\ub420 \uc218 \uc788\ub2e4","\uac70\ub798\uc758 \uc9c0\ub9ac\uc801 \ubc94\uc704\ub294 \uad00\ub828\uc2dc\uc7a5 \ud68d\uc815\uacfc \ubb34\uad00\ud558\uba70 \uc624\uc9c1 \uc0c1\ud488\uc758 \uc885\ub958\ub9cc\uc73c\ub85c \uc2dc\uc7a5\uc744 \ud68d\uc815\ud55c\ub2e4","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\ub294 \uac70\ub798\uc758 \uac1d\uccb4\xb7\ub2e8\uacc4\xb7\uc9c0\uc5ed\ubcc4\ub85c \ub2e4\ub974\uac8c \ub098\ud0c0\ub0a0 \uc218 \uc788\ub2e4"],t.s)
B.Ia=s(["\uc9c0\ub9ac\uc801 \ubc94\uc704\ub294 \uad00\ub828\uc2dc\uc7a5 \ud68d\uc815\uacfc \ubb34\uad00"],t.s)
B.Gv=s(["\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c","\uad00\ub828\uc2dc\uc7a5 \ud68d\uc815"],t.s)
B.Ny=new A.bA("gen_md_share_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c"(\uad00\ub828\uc2dc\uc7a5) \ud68d\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?',B.HH,3,'\uad00\ub828\uc2dc\uc7a5(\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c) \ud68d\uc815\uc740 \uc0c1\ud488\uc2dc\uc7a5\ubfd0 \uc544\ub2c8\ub77c \uc9c0\ub9ac\uc801 \uc2dc\uc7a5\ub3c4 \ud568\uaed8 \uace0\ub824\ud558\uc5ec \uc774\ub8e8\uc5b4\uc9c4\ub2e4. \uc218\uc694\uc790\uac00 \ub2e4\ub978 \uc9c0\uc5ed\uc758 \uacf5\uae09\uc790\ub85c\ubd80\ud130 \uc0c1\ud488\uc744 \uc870\ub2ec\ud560 \uc218 \uc788\ub294\uc9c0(\uc9c0\ub9ac\uc801 \ub300\uccb4\uac00\ub2a5\uc131) \uc5ed\uc2dc \uc2dc\uc7a5\uc9c0\ubc30\ub825 \ud310\ub2e8\uc5d0 \uc911\uc694\ud55c \uc694\uc18c\uc774\ubbc0\ub85c, "\uc9c0\ub9ac\uc801 \ubc94\uc704\ub294 \ubb34\uad00\ud558\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \uc2e4\ubb34\uc0c1 \uad00\ub828\uc2dc\uc7a5\uc740 \uc0c1\ud488\uc2dc\uc7a5\uacfc \uc9c0\uc5ed\uc2dc\uc7a5\uc744 \ud568\uaed8 \ud68d\uc815\ud55c \ub4a4 \uadf8 \uad50\uc9d1\ud569\uc744 \uae30\uc900\uc73c\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801 \uc9c0\uc704 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud55c\ub2e4.',B.Ia,B.Gv,null)
B.Ix=s(["\uc2dc\uc7a5\uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uc0c1\uc704 3\uac1c \uc0ac\uc5c5\uc790 \ud569\uc0b0 \uc810\uc720\uc728 \uacc4\uc0b0\uc5d0\uc11c \uc81c\uc678\ub41c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728 1\uc704 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\uc774 40%\uc774\uba74 \uadf8 \uc790\uccb4\ub9cc\uc73c\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ub41c\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uc740 \ud55c\ubc88 \uc131\ub9bd\ud558\uba74 \ubc18\uc99d\uc744 \ud1b5\ud574\uc11c\ub3c4 \ubc88\ubcf5\ud560 \uc218 \uc5c6\ub2e4","\uc5f0\uac04 \ub9e4\ucd9c\uc561 \ub610\ub294 \uacf5\uae09\ub7c9 \uae30\uc900 \uc911 \uc5b4\ub290 \ud558\ub098\ub9cc \uc0ac\uc6a9\ud560 \uc218 \uc788\uace0 \ubcd1\ud589 \uc0ac\uc6a9\uc740 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\ucd94\uc815 \uc694\uac74\uc744 \ucda9\uc871\ud558\ub294 \uc0ac\uc5c5\uc790\uac00 \ub2e4\uc218\uc778 \uacbd\uc6b0 \uadf8\uc911 1\uac1c \uc0ac\uc5c5\uc790\ub9cc \uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \uc9c0\uc815\ub41c\ub2e4"],t.s)
B.Ht=s(["\uc2dc\uc7a5\uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uadf8 \uc0b0\uc815\uc5d0\uc11c \uc81c\uc678"],t.s)
B.IL=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815","10% \ubbf8\ub9cc \uc81c\uc678"],t.s)
B.NC=new A.bA("gen_md_share_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740? (\uacc4\uc5f4\uad00\uacc4 \uc5c6\uc74c\uc744 \uc804\uc81c)",B.Ix,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc2dc\ud589\ub839\uc740 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0c1\uc704 3\uac1c \uc774\ud558 \uc0ac\uc5c5\uc790\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 75% \uc774\uc0c1\uc778 \uacbd\uc6b0\ub97c \ucd94\uc815 \uc694\uac74\uc73c\ub85c \uc0bc\ub418, \uc774\ub54c \uc2dc\uc7a5\uc810\uc720\uc728\uc774 10% \ubbf8\ub9cc\uc778 \uc0ac\uc5c5\uc790\ub294 \uadf8 \uc0b0\uc815\uc5d0\uc11c \uc81c\uc678\ud558\ub3c4\ub85d \uc815\ud558\uace0 \uc788\ub2e4. 1\uc704 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\uc774 50% \ubbf8\ub9cc(\uc608: 40%)\uc774\uba74 \ub2e8\ub3c5 \ucd94\uc815 \uc694\uac74(50% \uc774\uc0c1)\uc744 \ucda9\uc871\ud558\uc9c0 \ubabb\ud558\ubbc0\ub85c \uadf8 \uc790\uccb4\ub9cc\uc73c\ub85c \ucd94\uc815\ub418\uc9c0 \uc54a\uc73c\uba70, \ucd94\uc815\uc740 \ubc95\ub960\uc0c1 \ucd94\uc815\uc73c\ub85c\uc11c \ubc18\uc99d\uc744 \ud1b5\ud574 \ubc88\ubcf5\ub420 \uc218 \uc788\ub2e4. \ub9e4\ucd9c\uc561\xb7\uacf5\uae09\ub7c9 \uae30\uc900\uc740 \uc0ac\uc5c5\uc758 \ud2b9\uc131\uc5d0 \ub530\ub77c \uc801\uc808\ud788 \uc120\ud0dd\ub418\ub294 \uac83\uc774\uc9c0 \ubcd1\ud589 \uc0ac\uc6a9\uc774 \uae08\uc9c0\ub418\ub294 \uac83\ub3c4 \uc544\ub2c8\ub2e4.",B.Ht,B.IL,null)
B.HD=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c \uacc4\uc5f4\ud68c\uc0ac\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud569\uc0b0\ud558\uc5ec \uace0\ub824\ud55c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \uad00\uacc4\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ud310\ub2e8\uacfc \uc804\ud600 \uad00\ub828\uc774 \uc5c6\ub2e4","\uacc4\uc5f4\ud68c\uc0ac\uac00 \uba87 \uac1c\uc774\ub4e0 \ud569\uc0b0 \uc810\uc720\uc728\uc740 \ud56d\uc0c1 \ub2e8\ub3c5 \uc0ac\uc5c5\uc790\uc758 \uc810\uc720\uc728\ubcf4\ub2e4 \ub0ae\uac8c \uacc4\uc0b0\ub41c\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0\uc740 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \ud310\ub2e8\uc5d0\uc11c\ub9cc \uc801\uc6a9\ub418\uace0 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ud310\ub2e8\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uacc4\uc5f4\ud68c\uc0ac \uc5ec\ubd80\uc640 \ubb34\uad00\ud558\uac8c \uac1c\ubcc4 \ubc95\uc778\uc758 \uc810\uc720\uc728\ub9cc \ub3c5\ub9bd\uc801\uc73c\ub85c \ud310\ub2e8\ud55c\ub2e4"],t.s)
B.Ii=s(["\uacc4\uc5f4\ud68c\uc0ac\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud569\uc0b0\ud558\uc5ec \uace0\ub824\ud55c\ub2e4"],t.s)
B.Iz=s(["\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud310\ub2e8"],t.s)
B.Ne=new A.bA("gen_md_share_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacc4\uc5f4\ud68c\uc0ac\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud569\uc0b0\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.HD,0,"\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud560 \ub54c\ub294 \uc0ac\uc5c5\uc790\uac00 \uc18d\ud55c \uae30\uc5c5\uc9d1\ub2e8\uc758 \uacc4\uc5f4\ud68c\uc0ac \uc2dc\uc7a5\uc810\uc720\uc728\uc744 \ud569\uc0b0\ud558\uc5ec \uace0\ub824\ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ub2e4. \uc774\ub294 \ud615\uc2dd\uc801\uc73c\ub85c\ub294 \ubcc4\uac1c \ubc95\uc778\uc774\ub354\ub77c\ub3c4 \uc2e4\uc9c8\uc801\uc73c\ub85c \ub3d9\uc77c\ud55c \uc9c0\ubc30\ub825 \uc544\ub798 \uc788\ub294 \uacc4\uc5f4\ud68c\uc0ac\ub4e4\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\uc744 \uac1c\ubcc4\uc801\uc73c\ub85c\ub9cc \ubcf4\uba74 \uc2e4\uc81c \uc2dc\uc7a5\uc9c0\ubc30\ub825\uc744 \uacfc\uc18c\ud3c9\uac00\ud560 \uc704\ud5d8\uc774 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4. \ub530\ub77c\uc11c \uacc4\uc5f4\uad00\uacc4\uac00 \uc788\ub294 \uacbd\uc6b0 \ud569\uc0b0 \uc810\uc720\uc728\uc744 \uae30\uc900\uc73c\ub85c \ucd94\uc815 \uc694\uac74 \ucda9\uc871 \uc5ec\ubd80\ub97c \ud310\ub2e8\ud574\uc57c \ud55c\ub2e4.",B.Ii,B.Iz,null)
B.Fg=s(["\ucd94\uc815 \uaddc\uc815\uc740 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc785\uc99d \ubd80\ub2f4\uc744 \uc644\ud654\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4","\ucd94\uc815\uc744 \ubc1b\uc740 \uc0ac\uc5c5\uc790\ub294 \uc2e4\uc81c\ub85c\ub294 \uc2dc\uc7a5\uc9c0\ubc30\ub825\uc774 \uc5c6\ub2e4\ub294 \uc810\uc744 \ubc18\uc99d\ud558\uc5ec \ucd94\uc815\uc744 \ubc88\ubcf5\ud560 \uc218 \uc788\ub2e4","\ucd94\uc815 \uc694\uac74\uc740 \uc2dc\uc7a5\uc810\uc720\uc728\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70 \uc9c4\uc785\uc7a5\ubcbd\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790 \uc218 \ub4f1 \ub2e4\ub978 \uc0ac\uc815\uc740 \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc5d0\ub294 \uc0c1\ud488\uc774\ub098 \uc6a9\uc5ed\uc744 \uacf5\uae09\ud558\ub294 \uc0ac\uc5c5\uc790\ubfd0 \uc544\ub2c8\ub77c \uc218\uc694\uc790\uc758 \uc9c0\uc704\uc5d0 \uc788\ub294 \uc0ac\uc5c5\uc790\ub3c4 \ud3ec\ud568\ub420 \uc218 \uc788\ub2e4","\ucd94\uc815\uc744 \ubc1b\uc9c0 \uc54a\uc740 \uc0ac\uc5c5\uc790\ub3c4 \ub2e4\ub978 \uc0ac\uc815\uc744 \uadfc\uac70\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \uc778\uc815\ub420 \uc218 \uc788\ub2e4"],t.s)
B.J2=s(["\uc9c4\uc785\uc7a5\ubcbd\uc758 \uc874\uc7ac, \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc218\uc640 \uaddc\ubaa8, \uc720\uc0ac\ud488\xb7\uc778\uc811\uc2dc\uc7a5\uc758 \uc874\uc7ac \uc5ec\ubd80 \ub4f1 \ub2e4\uc591\ud55c \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824"],t.s)
B.Ff=s(["\uc2dc\uc7a5\uc9c0\ubc30\ub825 \uc2e4\uc9c8\ud310\ub2e8","\ucd94\uc815\uc758 \uc131\uaca9"],t.s)
B.Nn=new A.bA("gen_md_share_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uacfc \uad00\ub828\ud558\uc5ec \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Fg,2,'\uc2dc\uc7a5\uc810\uc720\uc728\uc5d0 \uc758\ud55c \ucd94\uc815\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ud310\ub2e8\uc744 \uc6a9\uc774\ud558\uac8c \ud558\uae30 \uc704\ud55c \ubc95\ub960\uc0c1 \ucd94\uc815\uc5d0 \ubd88\uacfc\ud558\uba70, \uc2e4\uc81c \uc2dc\uc7a5\uc9c0\ubc30\ub825 \uc720\ubb34\ub97c \ucd5c\uc885\uc801\uc73c\ub85c \ud310\ub2e8\ud560 \ub54c\ub294 \uc9c4\uc785\uc7a5\ubcbd\uc758 \uc874\uc7ac, \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc218\uc640 \uaddc\ubaa8, \uc720\uc0ac\ud488\xb7\uc778\uc811\uc2dc\uc7a5\uc758 \uc874\uc7ac \uc5ec\ubd80 \ub4f1 \ub2e4\uc591\ud55c \uc0ac\uc815\uc774 \ud568\uaed8 \uace0\ub824\ub41c\ub2e4. \ub530\ub77c\uc11c "\uc2dc\uc7a5\uc810\uc720\uc728\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \ud558\uba70 \ub2e4\ub978 \uc0ac\uc815\uc740 \uc804\ud600 \uace0\ub824\ub418\uc9c0 \uc54a\ub294\ub2e4"\ub294 \uc124\uba85\uc740 \uc633\uc9c0 \uc54a\ub2e4. \ucd94\uc815\uc744 \ubc1b\uc9c0 \ubabb\ud55c \uc0ac\uc5c5\uc790\ub77c\ub3c4 \uc774\ub7ec\ud55c \uc2e4\uc9c8\uc801 \uc0ac\uc815\uc5d0 \ub530\ub77c \uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \uc778\uc815\ub420 \uc218 \uc788\uace0, \ubc18\ub300\ub85c \ucd94\uc815\ub41c \uc0ac\uc5c5\uc790\ub3c4 \ubc18\uc99d\uc73c\ub85c \uc774\ub97c \ubc88\ubcf5\ud560 \uc218 \uc788\ub2e4.',B.J2,B.Ff,null)
B.I7=s(["\uc6d0\uce59\uc801\uc73c\ub85c \ucd5c\uadfc \uc0ac\uc5c5\uc5f0\ub3c4\uc758 \uad6d\ub0b4 \uacf5\uae09\ub41c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc758 \ub9e4\ucd9c\uc561 \ub610\ub294 \ub9e4\ucd9c\uc561 \ube44\uc728\ub85c \uc0b0\uc815\ud55c\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc624\uc9c1 \uc218\ucd9c\uc561\ub9cc\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4","\uc6a9\uc5ed\uc5c5\uc758 \uacbd\uc6b0 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0b0\uc815 \uc790\uccb4\uac00 \ubd88\uac00\ub2a5\ud558\ub2e4","\ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub3c4 \uacf5\uae09\ub7c9 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc5c6\ub2e4","\uc2dc\uc7a5\uc810\uc720\uc728\uc740 \ud56d\uc0c1 \uc804\uc138\uacc4 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4"],t.s)
B.H9=s(["\ucd5c\uadfc \uc0ac\uc5c5\uc5f0\ub3c4\uc758 \uad6d\ub0b4 \uacf5\uae09\ub41c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc758 \ub9e4\ucd9c\uc561 \ub610\ub294 \ub9e4\ucd9c\uc561 \ube44\uc728\ub85c \uc0b0\uc815"],t.s)
B.GC=s(["\uc2dc\uc7a5\uc810\uc720\uc728 \uc0b0\uc815\uae30\uc900"],t.s)
B.Nh=new A.bA("gen_md_share_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\uc2dc\uc7a5\uc810\uc720\uc728","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc810\uc720\uc728 \uc0b0\uc815 \uae30\uc900\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uac00\uc7a5 \uc633\uc740 \uac83\uc740?",B.I7,0,"\uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \ud574\ub2f9 \uc0ac\uc5c5\uc790\uac00 \ucd5c\uadfc \uc0ac\uc5c5\uc5f0\ub3c4\uc5d0 \uad6d\ub0b4\uc5d0\uc11c \uacf5\uae09\ud55c \uc0c1\ud488\xb7\uc6a9\uc5ed\uc758 \ub9e4\ucd9c\uc561(\ub610\ub294 \ub9e4\ucd9c\uc561 \ube44\uc728)\uc744 \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ud55c\ub2e4. \ub9e4\ucd9c\uc561 \uc0b0\uc815\uc774 \uace4\ub780\ud55c \uacbd\uc6b0\uc5d0\ub294 \uacf5\uae09\ub7c9, \uc0dd\uc0b0\ub2a5\ub825, \uc790\uc0b0\ucd1d\uc561 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \ud65c\uc6a9\ud574 \uc0b0\uc815\ud560 \uc218 \uc788\ub3c4\ub85d \ud558\uace0 \uc788\uc73c\uba70, \uc774\ub294 \uc0c1\ud488\uc5c5\ubfd0 \uc544\ub2c8\ub77c \uc6a9\uc5ed\uc5c5\uc5d0\ub3c4 \ub3d9\uc77c\ud558\uac8c \uc801\uc6a9\ub41c\ub2e4. \uad6d\ub0b4\uc2dc\uc7a5\uc744 \ub300\uc0c1\uc73c\ub85c \ud558\ub294 \uac83\uc774 \uc6d0\uce59\uc774\ubbc0\ub85c \uc218\ucd9c\uc561\uc774\ub098 \uc804\uc138\uacc4 \ub9e4\ucd9c\uc561\uc744 \uae30\uc900\uc73c\ub85c \ud558\uc9c0 \uc54a\ub294\ub2e4.",B.H9,B.GC,null)
B.H7=s(["\u3131, \u3134","\u3131, \u3137","\u3134, \u3137","\u3134, \u3139","\u3137, \u3139"],t.s)
B.Hf=s(["\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc5d0\uac8c \ud544\uc218\uc801\uc778 \uc694\uc18c(\uc124\ube44\xb7\uae30\uc220 \ub4f1)\uc758 \uc0ac\uc6a9\xb7\uc811\uadfc\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704(\u3137)\uac00 \ub300\ud45c\uc801"],t.s)
B.G3=s(["\uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704"],t.s)
B.Nm=new A.bA("gen_md_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704 \uc720\ud615 \uc911 \uc0c8\ub85c\uc6b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\ub798\ud558\ub294 \uc720\ud1b5\uc0ac\uc5c5\uc790\uc640 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \ud589\uc704\n\u3134. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ubc29\ud574\ud558\uae30 \uc704\ud574 \uc800\uac00\ub85c \uc0c1\ud488\uc744 \ud310\ub9e4\ud558\ub294 \ud589\uc704\n\u3137. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c8\ub85c\uc6b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488 \uc0dd\uc0b0\uc5d0 \ud544\uc218\uc801\uc778 \uc694\uc18c\uc758 \uc0ac\uc6a9\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704\n\u3139. \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uac00\uaca9\uc744 \uacb0\uc815\ud558\ub294 \ud589\uc704",B.H7,1,'\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc911 "\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704"\ub294 \uc0c8\ub85c\uc6b4 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0 \uc9c4\uc785\ud558\ub294 \uac83 \uc790\uccb4\ub97c \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc73c\ub85c, \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d \uccb4\uacb0(\u3131)\uacfc \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc5d0\uac8c \ud544\uc218\uc801\uc778 \uc694\uc18c(\uc124\ube44\xb7\uae30\uc220 \ub4f1)\uc758 \uc0ac\uc6a9\xb7\uc811\uadfc\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704(\u3137)\uac00 \ub300\ud45c\uc801\uc774\ub2e4. \ubc18\uba74 \u3134(\uc800\uac00 \ud310\ub9e4\ub85c \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574)\uc740 \uc774\ubbf8 \uc2dc\uc7a5\uc5d0 \uc874\uc7ac\ud558\ub294 \uc0ac\uc5c5\uc790\ub97c \uaca8\ub0e5\ud55c "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574" \uc720\ud615\uc774\uace0, \u3139(\uc18c\ube44\uc790\uc774\uc775\uc744 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uac00\uaca9 \uacb0\uc815)\uc740 \ubcc4\ub3c4\uc758 \ub3c5\uc790\uc801\uc778 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615(\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704)\uc73c\ub85c \ubd84\ub958\ub41c\ub2e4. \ub2e4\uc12f \uac00\uc9c0 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc744 \uc11c\ub85c \uad6c\ubd84\ud574\uc11c \uc554\uae30\ud558\ub294 \uac83\uc774 \uc774 \ucc55\ud130\uc758 \ud575\uc2ec\uc774\ub2e4.',B.Hf,B.G3,null)
B.Go=s(["\uc0c1\ud488\uc758 \uac00\uaca9\uc744 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ubd80\ub2f9\ud558\uac8c \uacb0\uc815\xb7\uc720\uc9c0 \ub610\ub294 \ubcc0\uacbd\ud558\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4","\uc6d0\uac00 \uc0c1\uc2b9 \ub4f1 \uc815\ub2f9\ud55c \uc0ac\uc720\uac00 \uc788\ub294 \uac00\uaca9 \uc778\uc0c1\uc740 \uc6d0\uce59\uc801\uc73c\ub85c \uac00\uaca9\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4","\uac00\uaca9\ubfd0\ub9cc \uc544\ub2c8\ub77c \uc6a9\uc5ed\uc758 \ub300\uac00\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc5d0 \ud3ec\ud568\ub41c\ub2e4","\uac00\uaca9\uc758 \uc778\uc0c1\ubfd0\ub9cc \uc544\ub2c8\ub77c \ubd80\ub2f9\ud55c \uc778\ud558\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4","\uac00\uaca9\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud558\ub824\uba74 \ubc18\ub4dc\uc2dc \uc2e4\uc81c\ub85c \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\uc5b4\uc57c \ud55c\ub2e4"],t.s)
B.GJ=s(["\uadf8\ub85c \uc778\ud574 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc2e4\uc81c\ub85c \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\ub294 \uacb0\uacfc\uae4c\uc9c0 \uc694\uad6c\ud558\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Ij=s(["\uac00\uaca9\ub0a8\uc6a9"],t.s)
B.Nc=new A.bA("gen_md_type_2","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 "\uac00\uaca9\ub0a8\uc6a9" \ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?',B.Go,4,"\uac00\uaca9\ub0a8\uc6a9\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac00\uaca9(\ub610\ub294 \uc6a9\uc5ed\uc758 \ub300\uac00)\uc744 \ubd80\ub2f9\ud558\uac8c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd\ud558\ub294 \ud589\uc704 \uc790\uccb4\ub97c \uaddc\uc81c\ud558\ub294 \uac83\uc73c\ub85c, \uadf8\ub85c \uc778\ud574 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uac00 \uc2e4\uc81c\ub85c \uc2dc\uc7a5\uc5d0\uc11c \ud1f4\ucd9c\ub418\ub294 \uacb0\uacfc\uae4c\uc9c0 \uc694\uad6c\ud558\uc9c0 \uc54a\ub294\ub2e4. \ubd80\ub2f9\uc131 \ud310\ub2e8\uc740 \uc6d0\uac00 \ubcc0\ub3d9 \uc694\uc778, \uc720\uc0ac \uc2dc\uc7a5\uc758 \uac00\uaca9 \uc218\uc900, \uc774\uc724 \ud3ed\uc758 \ubcc0\ud654 \ub4f1\uc744 \uc885\ud569\uc801\uc73c\ub85c \uace0\ub824\ud558\uba70, \uc778\uc0c1\ubfd0 \uc544\ub2c8\ub77c \ubd80\ub2f9\ud55c \uc778\ud558(\uc6d0\uac00 \uc774\ud558 \ud310\ub9e4\ub97c \ud1b5\ud55c \uacbd\uc7c1\uc81c\ud55c \ub4f1)\ub3c4 \uaddc\uc81c \ub300\uc0c1\uc774 \ub420 \uc218 \uc788\ub2e4.",B.GJ,B.Ij,null)
B.GX=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c1\ud488\uc758 \uacf5\uae09\ub7c9\uc744 \ucd5c\uadfc\uc758 \ucd94\uc138\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ud0a4\ub294 \ud589\uc704","\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uc774\uc775\uc744 \uc81c\uacf5\ud558\ub3c4\ub85d \uac15\uc694\ud558\ub294 \ud589\uc704","\uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\uae30 \uc704\ud558\uc5ec \uc815\uc0c1\uac70\ub798\uad00\ud589\uc5d0 \ube44\ucd94\uc5b4 \uc774\ub840\uc801\uc778 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \ubc29\ud574\ud558\ub294 \ud589\uc704"],t.s)
B.J0=s(["\uc0c1\ud488\uc758 \uc0dd\uc0b0\xb7\ucd9c\uace0\xb7\ud310\ub9e4\ub97c \ucd5c\uadfc\uc758 \ucd94\uc138\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ud0a4\uac70\ub098 \uc99d\uac00\uc2dc\ucf1c"],t.s)
B.IH=s(["\ucd9c\uace0\uc870\uc808"],t.s)
B.Nv=new A.bA("gen_md_type_3","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 "\ucd9c\uace0\uc870\uc808" \ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc740?',B.GX,0,"\ucd9c\uace0\uc870\uc808\uc740 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c1\ud488\uc758 \uc0dd\uc0b0\xb7\ucd9c\uace0\xb7\ud310\ub9e4\ub97c \ucd5c\uadfc\uc758 \ucd94\uc138\uc5d0 \ube44\ucd94\uc5b4 \ud604\uc800\ud788 \uac10\uc18c\uc2dc\ud0a4\uac70\ub098 \uc99d\uac00\uc2dc\ucf1c \uc0c1\ud488 \uc218\uae09\uc5d0 \uc778\uc704\uc801 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \ud589\uc704\ub97c \ub9d0\ud55c\ub2e4. \uc774\ub294 \uc2dc\uc7a5\uc758 \uc218\uae09\uc744 \uc778\uc704\uc801\uc73c\ub85c \uc870\uc791\ud558\uc5ec \uac00\uaca9\uc774\ub098 \uac70\ub798\uc870\uac74\uc5d0 \ubd80\ub2f9\ud55c \uc601\ud5a5\uc744 \ubbf8\uce58\ub824\ub294 \ud589\uc704\ub85c\uc11c, \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\xb7\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\uc640\ub294 \uad6c\ubcc4\ub418\ub294 \ub3c5\uc790\uc801\uc778 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uc774\ub2e4.",B.J0,B.IH,null)
B.IT=s(["\u3131, \u3134","\u3131, \u3137","\u3134, \u3137","\u3131, \u3134, \u3137","\u3134\ub9cc"],t.s)
B.IQ=s(["\ud544\uc218\uc694\uc18c \uc0ac\uc6a9 \uac70\uc808(\u3131), \uc6d0\uc7ac\ub8cc \uad6c\ub9e4 \ubc29\ud574(\u3134), \uc778\ub825 \ucc44\uc6a9 \ubc29\ud574 \ub4f1\uc774 \ub300\ud45c\uc801 \uc720\ud615"],t.s)
B.Ib=s(["\uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"],t.s)
B.Nf=new A.bA("gen_md_type_4","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 "\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488 \uc0dd\uc0b0\xb7\ud310\ub9e4\uc5d0 \ud544\uc218\uc801\uc778 \uc694\uc18c\uc758 \uc0ac\uc6a9\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704\n\u3134. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc6d0\uc7ac\ub8cc \uad6c\ub9e4\ub97c \ubc29\ud574\ud558\ub294 \ud589\uc704\n\u3137. \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uc0c1\ud488 \ud310\ub9e4\ub97c \ud558\ub294 \ud589\uc704',B.IT,0,'"\ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704"\ub294 \uc774\ubbf8 \uc2dc\uc7a5\uc5d0 \uc874\uc7ac\ud558\ub294 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc5b4\ub835\uac8c \ub9cc\ub4dc\ub294 \ud589\uc704\ub85c, \ud544\uc218\uc694\uc18c \uc0ac\uc6a9 \uac70\uc808(\u3131), \uc6d0\uc7ac\ub8cc \uad6c\ub9e4 \ubc29\ud574(\u3134), \uc778\ub825 \ucc44\uc6a9 \ubc29\ud574 \ub4f1\uc774 \ub300\ud45c\uc801 \uc720\ud615\uc774\ub2e4. \ubc18\uba74 \u3137(\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574 \uc6b0\ub824\uac00 \uc788\ub294 \uc0c1\ud488 \ud310\ub9e4)\uc740 \ubcc4\ub3c4\ub85c \ubd84\ub958\ub418\ub294 "\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704" \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574\ud589\uc704\uc640 \uad6c\ubd84\ud574\uc57c \ud55c\ub2e4.',B.IQ,B.Ib,null)
B.Ip=s(["\ubd80\ub2f9\ud558\uac8c \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\ub85c\uc11c \ub2e4\ub978 4\uac00\uc9c0 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uacfc\ub294 \ubcc4\ub3c4\ub85c \uaddc\uc815\ub41c \ubcf4\ucda9\uc801 \uc720\ud615\uc774\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \ubc18\ub4dc\uc2dc \uac00\uaca9 \uc778\uc0c1\uc744 \uc218\ubc18\ud558\uc5ec\uc57c \uc131\ub9bd\ud55c\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc5d0\uac8c\ub9cc \uc801\uc6a9\ub41c\ub2e4","\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\uac00 \uc131\ub9bd\ud558\ub824\uba74 \uc2e4\uc81c \uc18c\ube44\uc790 \ud53c\ud574\uac00 \ud655\uc815\uc801\uc73c\ub85c \ubc1c\uc0dd\ud574\uc57c \ud55c\ub2e4"],t.s)
B.GE=s(["\ub2e4\ub978 4\uac00\uc9c0 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uacfc\ub294 \ubcc4\ub3c4\ub85c \uaddc\uc815\ub41c \ubcf4\ucda9\uc801 \uc720\ud615"],t.s)
B.Hp=s(["\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704"],t.s)
B.Nk=new A.bA("gen_md_type_5","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 "\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704"\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?',B.Ip,0,'\uc18c\ube44\uc790\uc774\uc775 \uc800\ud574\ud589\uc704\ub294 \ubd80\ub2f9\ud558\uac8c \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\ub97c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc73c\ub85c, \uac00\uaca9\ub0a8\uc6a9\xb7\ucd9c\uace0\uc870\uc808\xb7\uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574\xb7\uc2dc\uc7a5\ucc38\uac00\ubc29\ud574\xb7\uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c\ub77c\ub294 \ub2e4\ub978 \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub354\ub77c\ub3c4 \uc18c\ube44\uc790 \uc774\uc775\uc744 \ud604\uc800\ud788 \uce68\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub2e4\uba74 \uaddc\uc81c\ud560 \uc218 \uc788\ub3c4\ub85d \ub9c8\ub828\ub41c \ubcf4\ucda9\uc801\xb7\ud3ec\uad04\uc801 \uc131\uaca9\uc758 \uc720\ud615\uc774\ub2e4. "\uc6b0\ub824\uac00 \uc788\ub294" \ud589\uc704\ub97c \uaddc\uc81c \ub300\uc0c1\uc73c\ub85c \ud558\ubbc0\ub85c \uc2e4\uc81c \ud53c\ud574\uac00 \ud655\uc815\uc801\uc73c\ub85c \ubc1c\uc0dd\ud560 \uac83\uae4c\uc9c0 \uc694\uad6c\ud558\uc9c0 \uc54a\uc73c\uba70, \uac00\uaca9 \uc778\uc0c1\uc744 \ubc18\ub4dc\uc2dc \uc218\ubc18\ud574\uc57c \ud558\ub294 \uac83\ub3c4 \uc544\ub2c8\ub2e4.',B.GE,B.Hp,null)
B.Id=s(["\uac00\uaca9\ub0a8\uc6a9 \u2013 \ucd9c\uace0\uc870\uc808 \u2013 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574 \u2013 \uc2dc\uc7a5\ucc38\uac00\ubc29\ud574 \u2013 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c\xb7\uc18c\ube44\uc790\uc774\uc775\uc800\ud574","\uac00\uaca9\ub0a8\uc6a9 \u2013 \ubd80\ub2f9\uc5fc\ub9e4 \u2013 \uac70\ub798\uac70\uc808 \u2013 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \u2013 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\uac00\uaca9\ub0a8\uc6a9 \u2013 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0 \u2013 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704 \u2013 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574 \u2013 \uc2dc\uc7a5\ucc38\uac00\ubc29\ud574","\ucd9c\uace0\uc870\uc808 \u2013 \ub2f4\ud569 \u2013 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \u2013 \uc2dc\uc7a5\ucc38\uac00\ubc29\ud574 \u2013 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ubc30\uc81c","\uac00\uaca9\ub0a8\uc6a9 \u2013 \ucd9c\uace0\uc870\uc808 \u2013 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704 \u2013 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798 \u2013 \uc18c\ube44\uc790\uc774\uc775\uc800\ud574"],t.s)
B.Iv=s(["\uac00\uaca9\ub0a8\uc6a9, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c"],t.s)
B.Gi=s(["\ub0a8\uc6a9\ud589\uc704 5\uc720\ud615 \ucd1d\uc815\ub9ac"],t.s)
B.Ns=new A.bA("gen_md_type_6","economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ud589\uc704 \uc720\ud615","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 5\uac00\uc9c0 \uc720\ud615\uc744 \uc62c\ubc14\ub974\uac8c \uc5f0\uacb0\ud55c \uac83\uc740?",B.Id,0,"\uacf5\uc815\uac70\ub798\ubc95 \uc81c5\uc870\uac00 \uc815\ud558\ub294 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704\uc758 5\uac00\uc9c0 \uc720\ud615\uc740 \u2460 \uac00\uaca9\ub0a8\uc6a9, \u2461 \ucd9c\uace0\uc870\uc808, \u2462 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9 \ubc29\ud574, \u2463 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574, \u2464 \uacbd\uc7c1\uc0ac\uc5c5\uc790\ub97c \ubc30\uc81c\ud558\uae30 \uc704\ud55c \uac70\ub798 \ub610\ub294 \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \ud589\uc704\uc774\ub2e4. \ubd80\ub2f9\uc5fc\ub9e4\xb7\uac70\ub798\uac70\uc808\xb7\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\xb7\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\xb7\ub2f4\ud569\xb7\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \ub4f1\uc740 \ubaa8\ub450 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\ub098 \ubd80\ub2f9\uacf5\ub3d9\ud589\uc704 \ub4f1 \ub2e4\ub978 \ub300\ubd84\ub958\uc5d0 \uc18d\ud558\ub294 \uac1c\ub150\uc774\ubbc0\ub85c \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9\ud589\uc704 \uc720\ud615\uacfc \ud63c\ub3d9\ud558\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4.",B.Iv,B.Gi,null)
B.HO=s(["\uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud589\uc704\ub85c \uc778\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0 \uc774 \ubc95\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294\uc9c0 \uc5ec\ubd80\ub294 \uc9c1\uc811\uc801\uc774\uace0 \uc0c1\ub2f9\ud558\uba70 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc744 \uae30\uc900\uc73c\ub85c \uc81c\ud55c \ud574\uc11d\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uc678\uad6d \ubc95\ub960\uc0c1 \uc801\ubc95\ud558\ub2e4\uba74 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc774 \ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub41c\ub2e4","\uc815\ubd80\ub294 \ub300\ud55c\ubbfc\uad6d\uc758 \ubc95\ub960 \ubc0f \uc774\uc775\uc5d0 \ubc18\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uc678\uad6d\uc815\ubd80\uc640 \uc774 \ubc95 \uc9d1\ud589\uc744 \uc704\ud55c \ud611\uc815\uc744 \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uadfc\uac70 \uc870\ubb38\uc740 \uc774 \ubc95 \uc81c\uc815 \ub2f9\uc2dc\ubd80\ud130 \uc874\uc7ac\ud55c \uac83\uc740 \uc544\ub2c8\ub2e4"],t.s)
B.Hi=s(["\uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ud310\uc2dc"],t.s)
B.HC=s(["\uc5ed\uc678\uc801\uc6a9"],t.s)
B.Nd=new A.bA("gen_gn_1","economic_law","\ubaa9\uc801\xb7\ucd1d\uce59",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc758 \uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.HO,2,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c3\uc870\ub294 \uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud6a8\uacfc\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0\uc5d0\ub294 \uc774 \ubc95\uc744 \uc801\uc6a9\ud55c\ub2e4\ub294 \uc5ed\uc678\uc801\uc6a9 \uc6d0\uce59\uc744 \uba85\uc2dc\ud558\uace0 \uc788\ub2e4. \ub300\ubc95\uc6d0 \ud310\ub840(\ud751\uc5f0\uc804\uadf9\ubd09 \uc0ac\uac74 \ub4f1)\ub294 \uc774\ub54c "\uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294 \uacbd\uc6b0"\ub97c \ubb38\uc81c\ub41c \uad6d\uc678\ud589\uc704\ub85c \uc778\ud574 \uc9c1\uc811\uc801\xb7\uc0c1\ub2f9\ud558\uace0 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0\ub85c \uc81c\ud55c \ud574\uc11d\ud558\ub418, \uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uadf8 \uc678\uad6d \ubc95\ub960\uc0c1\uc73c\ub85c\ub294 \uc801\ubc95\ud55c \ud589\uc704\uc600\ub2e4 \ud558\ub354\ub77c\ub3c4 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \uacf5\uc815\uac70\ub798\ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\uace0 \ud310\uc2dc\ud558\uc600\ub2e4. \uc989 "\uc678\uad6d\uc5d0\uc11c \uc801\ubc95 = \uad6d\ub0b4\ubc95 \uc801\uc6a9 \ubc30\uc81c"\ub77c\ub294 \ub4f1\uc2dd\uc740 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4\ub294 \uc810\uc774 \uc774 \ubb38\uc81c\uc758 \ud575\uc2ec\uc774\uba70, \uad6d\uac00 \uac04 \ud611\uc815 \uccb4\uacb0 \uadfc\uac70(\uc81c56\uc870)\ub098 \uc5ed\uc678\uc801\uc6a9 \uc870\ubb38\uc758 \uc2e0\uc124 \uc5f0\ud601\ub3c4 \ud568\uaed8 \uc54c\uc544\ub450\uc5b4\uc57c \ud55c\ub2e4.',B.Hi,B.HC,null)
B.GZ=s(["\ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \uacf5\ub3d9\ud589\uc704\ub85c \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc758 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798\uc758 \uc0ac\uc5c5\uc790 \uc218\ub97c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9 \ub610\ub294 \ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\ub3c4\ub85d \ubc29\uc870\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc0c1\ud488 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"],t.s)
B.Fi=s(['"\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c"\ub85c\uc11c, \uc774\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc758 \ud558\uc704 \uc720\ud615\uc5d0 \ud574\ub2f9\ud560 \ubfd0'],t.s)
B.HI=s(["\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uc720\ud615"],t.s)
B.NA=new A.bA("gen_ta_1","economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.GZ,4,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c51\uc870\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704\ub85c \u2460 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub97c \ud1b5\ud55c \uacbd\uc7c1\uc81c\ud55c, \u2461 \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798\uc758 \uc0ac\uc5c5\uc790 \uc218 \uc81c\ud55c, \u2462 \uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9\xb7\ud65c\ub3d9\uc758 \ubd80\ub2f9\ud55c \uc81c\ud55c, \u2463 \uc0ac\uc5c5\uc790\uc5d0\uac8c \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704\xb7\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\uac8c \ud558\uac70\ub098 \ubc29\uc870\ud558\ub294 \ud589\uc704\ub97c \uc5f4\uac70\ud558\uace0 \uc788\ub2e4. \ubc18\uba74 "\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc0c1\ud488 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uac00 \uc544\ub2c8\ub77c \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ud589\ud558\ub294 "\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c"\ub85c\uc11c, \uc774\ub294 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc911 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc758 \ud558\uc704 \uc720\ud615\uc5d0 \ud574\ub2f9\ud560 \ubfd0 \ubc95 \uc81c51\uc870\uac00 \uc5f4\uac70\ud558\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uace0\uc720\uc758 \uae08\uc9c0\ud589\uc704 \uc720\ud615\uc5d0\ub294 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.Fi,B.HI,null)
B.HA=s(["\uc0ac\uc5c5\uc790\uac00 \uc0c1\ud488\uc744 \uac70\ub798\ud558\uba70 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud558\uc5ec \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\ud558\ub3c4\ub85d \uac15\uc81c\ud558\ub294 \ud589\uc704\ub294 \uad6c\uc18d\ub825 \uc5ec\ubd80\uc640 \uc0c1\uad00\uc5c6\uc774 \ud56d\uc0c1 \uae08\uc9c0\ub41c\ub2e4","\uc800\uc791\uad8c\ubc95\uc0c1 \uc800\uc791\ubb3c\ub85c\uc11c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc0c1\ud488\uc758 \uacbd\uc6b0 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub420 \uc218 \uc788\ub2e4","\ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\uc5b4\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uae08\uc9c0\ub294 \uc6a9\uc5ed\uc758 \uc81c\uacf5\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uac15\uc81c\ub825 \uc5c6\ub294 \ud76c\ub9dd\uac00\uaca9\uc744 \uc81c\uc2dc\ud558\ub294 \ud589\uc704\ub3c4 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c \uae08\uc9c0\ub41c\ub2e4"],t.s)
B.Ie=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc804\uc790\ucd9c\ud310\ubb3c \ub4f1\uc5d0 \ub300\ud574\uc11c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub41c\ub2e4"],t.s)
B.Gu=s(["\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uc608\uc678"],t.s)
B.ND=new A.bA("gen_rp_1","economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.HA,1,'\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc0ac\uc5c5\uc790\uac00 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud574 \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\ud558\ub3c4\ub85d \uac15\uc81c\ud558\uac70\ub098 \uad6c\uc18d\uc870\uac74\uc744 \ubd99\uc774\ub294 \ud589\uc704\ub85c \uc6d0\uce59\uc801\uc73c\ub85c \uae08\uc9c0\ub41c\ub2e4(\uacf5\uc815\uac70\ub798\ubc95 \uc81c46\uc870). \ub2e4\ub9cc \uc608\uc678\uc801\uc73c\ub85c \u300c\uc800\uc791\uad8c\ubc95\u300d\uc0c1 \uc800\uc791\ubb3c \uc911 \uad00\uacc4 \uc911\uc559\ud589\uc815\uae30\uad00\uc758 \uc7a5\uacfc \ud611\uc758\ub97c \uac70\uccd0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc804\uc790\ucd9c\ud310\ubb3c \ub4f1\uc5d0 \ub300\ud574\uc11c\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub41c\ub2e4. \ubc18\uba74 \ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub3c4 "\uc815\ub2f9\ud55c \uc774\uc720"\uac00 \uc788\uc73c\uba74 \ud5c8\uc6a9\ub420 \uc218 \uc788\uace0(\uc120\ud0dd\uc9c0 \u2462\uc740 \uc624\ub2f5), \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc0c1\ud488\ubfd0 \uc544\ub2c8\ub77c \uc6a9\uc5ed\uc758 \uc81c\uacf5\uc5d0\ub3c4 \uc801\uc6a9\ub418\uba70(\uc120\ud0dd\uc9c0 \u2463\ub294 \uc624\ub2f5), \uac15\uc81c\ub825 \uc5c6\ub294 \ub2e8\uc21c \ud76c\ub9dd\uac00\uaca9 \uc81c\uc2dc\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4(\uc120\ud0dd\uc9c0 \u2464\ub294 \uc624\ub2f5)\ub294 \uc810\ub3c4 \ud568\uaed8 \uc815\ub9ac\ud574\uc57c \ud55c\ub2e4.',B.Ie,B.Gu,null)
B.Fp=s(["\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uae08\uc744 \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc0ac\uc5c5\uae30\ud68c\ub97c \uc81c\uacf5\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\ud569\ub9ac\uc801 \uace0\ub824\ub098 \ube44\uad50 \uc5c6\uc774 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\ub85c \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc2dc\uc7a5\uac00\uaca9\ubcf4\ub2e4 \ub0ae\uc740 \uac00\uaca9\uc73c\ub85c \uc77c\ubc18 \uc18c\ube44\uc790\uc5d0\uac8c \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\uc744 \uc81c\uacf5\ud558\ub294 \ud589\uc704"],t.s)
B.GK=s(["\uc77c\ubc18 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud55c \ud1b5\uc0c1\uc801\uc778 \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\ucc98\ub7fc \ud2b9\uc218\uad00\uacc4\uc778\uacfc \ubb34\uad00\ud55c \uac70\ub798\ub294 \uc560\ucd08\uc5d0 \uaddc\uc81c \ub300\uc0c1 \ubc94\uc704\uc5d0 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.GM=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc77c\uac10\ubab0\uc544\uc8fc\uae30"],t.s)
B.Nr=new A.bA("gen_sp_1","economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\ud55c \uc774\uc775\uc81c\uacf5\ud589\uc704(\uc0ac\uc775\ud3b8\ucde8)\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.Fp,4,'\uacf5\uc815\uac70\ub798\ubc95 \uc81c47\uc870(\ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\ud55c \uc774\uc775\uc81c\uacf5 \ub4f1 \uae08\uc9c0, \uc774\ub978\ubc14 "\uc77c\uac10\ubab0\uc544\uc8fc\uae30" \uaddc\uc81c)\ub294 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc758 \uc790\uae08\xb7\uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\xb7\uc778\ub825 \uac70\ub798, \uc0ac\uc5c5\uae30\ud68c \uc81c\uacf5, \ud569\ub9ac\uc801 \uace0\ub824 \uc5c6\ub294 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\uc758 \uac70\ub798\ub97c \ud1b5\ud574 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704\ub97c \uae08\uc9c0 \ub300\uc0c1\uc73c\ub85c \uaddc\uc815\ud55c\ub2e4. \uc774 \uaddc\uc81c\uc758 \ubaa9\uc801\uc740 \ub300\uae30\uc5c5\uc9d1\ub2e8 \ucd1d\uc218 \uc77c\uac00\ub098 \uacc4\uc5f4\ud68c\uc0ac \ub4f1 "\ud2b9\uc218\uad00\uacc4\uc778"\uc5d0\uac8c \ubd80\ub97c \ubd80\ub2f9\ud558\uac8c \uc774\uc804\uc2dc\ud0a4\ub294 \uac83\uc744 \ub9c9\ub294 \ub370 \uc788\uc73c\ubbc0\ub85c, \uc77c\ubc18 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud55c \ud1b5\uc0c1\uc801\uc778 \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\ucc98\ub7fc \ud2b9\uc218\uad00\uacc4\uc778\uacfc \ubb34\uad00\ud55c \uac70\ub798\ub294 \uc560\ucd08\uc5d0 \uaddc\uc81c \ub300\uc0c1 \ubc94\uc704\uc5d0 \ud3ec\ud568\ub418\uc9c0 \uc54a\ub294\ub2e4.',B.GK,B.GM,null)
B.II=s(["\ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \ud574\ub2f9 \uc0ac\uac74\uc5d0 \ub300\ud55c \uc2ec\uc758\uc808\ucc28\ub294 \uc885\ub8cc\ub41c\ub2e4","\uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc54a\uc73c\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc774\ud589\uac15\uc81c\uae08\uc744 \ubd80\uacfc\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \ud5a5\ud6c4 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc18c\uc1a1\uc5d0\uc11c \uc2e0\uccad\uc778\uc740 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc790\ubc31\ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\uc5b4 \uc6d0\uace0\uc758 \uc785\uc99d\ucc45\uc784\uc774 \uba74\uc81c\ub41c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub3d9\uc758\uc758\uacb0\uc758 \uc774\ud589\uc2e4\ud0dc\ub97c \uc810\uac80\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \ucde8\uc18c\ub41c \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc911\ub2e8\ub418\uc5c8\ub358 \uc6d0\ub798\uc758 \uc2ec\uc758\uc808\ucc28\ub97c \uacc4\uc18d\ud560 \uc218 \uc788\ub2e4"],t.s)
B.IJ=s(["\uc2e0\uccad\uc778\uc774 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc790\ubc31\ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\uc9c0 \uc54a\ub294\ub2e4"],t.s)
B.Gw=s(["\ub3d9\uc758\uc758\uacb0\uc81c\ub3c4","\uc190\ud574\ubc30\uc0c1\uacfc\uc758 \uad00\uacc4"],t.s)
B.NB=new A.bA("gen_pc_4","economic_law","\ub3d9\uc758\uc758\uacb0",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub41c \uc774\ud6c4\uc758 \ud6a8\uacfc\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.II,2,"\ub3d9\uc758\uc758\uacb0\uc740 \uc0ac\uc5c5\uc790\uac00 \uc81c\ucd9c\ud55c \uc2dc\uc815\ubc29\uc548\uacfc \uac19\uc740 \ucde8\uc9c0\ub85c \uc0ac\uac74\uc744 \uc885\uacb0\ud558\ub294 \uac83\uc77c \ubfd0 \ud574\ub2f9 \ud589\uc704\uac00 \ubc95\uc5d0 \uc704\ubc18\ub41c\ub2e4\uace0 \uc778\uc815\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ubbc0\ub85c, \uc774\ud6c4 \uc81c\uae30\ub418\ub294 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc18c\uc1a1\uc5d0\uc11c \uc2e0\uccad\uc778\uc774 \uc704\ubc18\uc0ac\uc2e4\uc744 \uc790\ubc31\ud55c \uac83\uc73c\ub85c \uac04\uc8fc\ub418\uc9c0 \uc54a\ub294\ub2e4. \uc989 \ud53c\ud574\uc790\ub294 \ub3d9\uc758\uc758\uacb0\uacfc\ub294 \ubcc4\ub3c4\ub85c \uc704\ubc95\uc131\xb7\uc778\uacfc\uad00\uacc4\xb7\uc190\ud574\uc561\uc744 \uc2a4\uc2a4\ub85c \uc99d\uba85\ud574\uc57c \ud55c\ub2e4. \ub3d9\uc758\uc758\uacb0\uc774 \ud655\uc815\ub418\uba74 \uc2ec\uc758\uc808\ucc28\uac00 \uc885\ub8cc\ub418\uace0, \ubd88\uc774\ud589 \uc2dc \uc774\ud589\uac15\uc81c\uae08 \ubd80\uacfc\xb7\uc774\ud589\uc2e4\ud0dc \uc810\uac80\xb7\ub3d9\uc758\uc758\uacb0 \ucde8\uc18c \ud6c4 \uc6d0\ub798 \uc808\ucc28 \uc7ac\uac1c\uac00 \uac00\ub2a5\ud558\ub2e4\ub294 \ub098\uba38\uc9c0 \uc120\ud0dd\uc9c0\ub4e4\uc740 \ubaa8\ub450 \uc633\uc740 \uc124\uba85\uc774\ub2e4.",B.IJ,B.Gw,null)
B.Fk=s(["\uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9 \ubc0f \uc815\ub3c4","\uc704\ubc18\ud589\uc704\uc758 \uae30\uac04 \ubc0f \ud69f\uc218","\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\uc5d0\uc11c\uc758 \uc9c0\uc704","\uc704\ubc18\ud589\uc704\ub85c \ucde8\ub4dd\ud55c \uc774\uc775\uc758 \uaddc\ubaa8","\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc784\uc9c1\uc6d0 \uc218"],t.s)
B.Is=s(['\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc784\uc9c1\uc6d0 \uc218"\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815\uc758 \ubc95\uc815 \uace0\ub824\uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4'],t.s)
B.FK=s(["\uacfc\uc9d5\uae08 \uc0b0\uc815\uae30\uc900"],t.s)
B.Nb=new A.bA("gen_pc_5","economic_law","\uacfc\uc9d5\uae08",null,"\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacfc\uc9d5\uae08 \uc0b0\uc815 \uc2dc \uace0\ub824\ud558\ub294 \uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Fk,4,'\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \ub54c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\ub824\ud558\ub294 \uc694\uc18c\ub294 \uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9\xb7\uc815\ub3c4, \uae30\uac04\xb7\ud69f\uc218, \uc704\ubc18\ud589\uc704\ub85c \ucde8\ub4dd\ud55c \uc774\uc775\uc758 \uaddc\ubaa8 \ub4f1\uc774\uba70, \uc774\ub294 \uc704\ubc18\ud589\uc704\uc758 \uc911\ub300\uc131\uacfc \ubd80\ub2f9\uc774\ub4dd\uc758 \uaddc\ubaa8\uc5d0 \ube44\ub840\ud558\uc5ec \uc81c\uc7ac \uc218\uc900\uc744 \uc815\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4. \ubc18\uba74 "\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc784\uc9c1\uc6d0 \uc218"\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815\uc758 \ubc95\uc815 \uace0\ub824\uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4 \u2014 \uacfc\uc9d5\uae08\uc740 \uc5b4\ub514\uae4c\uc9c0\ub098 \uc704\ubc18\ud589\uc704 \uc790\uccb4\uc758 \uacbd\uc911\uacfc \uadf8\ub85c \uc778\ud55c \uc774\ub4dd \uaddc\ubaa8\ub97c \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ub418\ub294 \uac83\uc774\uc9c0, \uae30\uc5c5\uc758 \uc870\uc9c1 \uaddc\ubaa8(\uc784\uc9c1\uc6d0 \uc218)\ub97c \uc9c1\uc811\uc801\uc778 \uc0b0\uc815 \uae30\uc900\uc73c\ub85c \uc0bc\uc9c0 \uc54a\ub294\ub2e4.',B.Is,B.FK,null)
B.G9=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\uc5d0\uc11c \uc815\ud55c \uac83\ubcf4\ub2e4 \ub0ae\uc740 \ub300\uae08\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc9c0\uae09\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \uc0c1\ud488\uacfc \ud568\uaed8 \ub2e4\ub978 \uc0c1\ud488\uc758 \uad6c\uc785\uc744 \uac15\uc81c\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uac00 \uc9c0\uc815\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488\uc744 \uad6c\uc785\ud558\ub3c4\ub85d \uac15\uc694\ud558\ub294 \ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \ubc30\ud0c0\uc870\uac74\uc744 \ubd99\uc774\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ud2b9\uc815 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"],t.s)
